    ('SPH-I 140', 'BEGINNING BRAZILIAN JU-JITSU', '10136', 'Class Status', 'MW Monday, Wednesday 12:45 PM–1:35 PM', 'GF 199', 'John Gordon', 1, NULL, 'Activity', '1', 'BILL GARRETT FIELDHOUSE', ARRAY[]::TEXT[], 'Instruction in the basic ground fighting techniques, throwing, joint locks, chokes, and some self-defense derived from Caique Brazilian Ju-Jitsu. Students should achieve rudimentary technical skill and learn the philosophy and concepts used in ground-fighting martial art practice as well as applying these concepts to competitive ground fighting. Focus is placed on body posturing, position control, flow-drills, and submission techniques.', ARRAY[]::TEXT[], NULL),
    ('SPH-I 140', 'BEGINNING BRAZILIAN JU-JITSU', '10137', 'Class Status', 'TuTh Tuesday, Thursday 9:10 AM–10:00 AM', 'GF 199', 'Gregory Lucas', 2, NULL, 'Activity', '1', 'BILL GARRETT FIELDHOUSE', ARRAY[]::TEXT[], 'Instruction in the basic ground fighting techniques, throwing, joint locks, chokes, and some self-defense derived from Caique Brazilian Ju-Jitsu. Students should achieve rudimentary technical skill and learn the philosophy and concepts used in ground-fighting martial art practice as well as applying these concepts to competitive ground fighting. Focus is placed on body posturing, position control, flow-drills, and submission techniques.', ARRAY[]::TEXT[], NULL),
    ('SPH-I 140', 'BEGINNING BRAZILIAN JU-JITSU', '10138', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–1:35 PM', 'GF 199', 'Gregory Lucas', 1, NULL, 'Activity', '1', 'BILL GARRETT FIELDHOUSE', ARRAY[]::TEXT[], 'Instruction in the basic ground fighting techniques, throwing, joint locks, chokes, and some self-defense derived from Caique Brazilian Ju-Jitsu. Students should achieve rudimentary technical skill and learn the philosophy and concepts used in ground-fighting martial art practice as well as applying these concepts to competitive ground fighting. Focus is placed on body posturing, position control, flow-drills, and submission techniques.', ARRAY[]::TEXT[], NULL),
    ('SPH-I 143', 'MODERN ARNIS', '11572', 'Class Status', 'F Friday 11:35 AM–1:15 PM', 'GF 199', 'Jason Gearheart', 5, NULL, 'Activity', '1', 'BILL GARRETT FIELDHOUSE', ARRAY[]::TEXT[], 'Instruction in basic weapon handling and self-defense using concepts and drills taken from the Remy Presas Modern Arnis system. Students should achieve rudimentary technical skill and learn the philosophy and concepts to empty-hand martial art practice as well as applying these concepts to empty-hand martial art practice. Focus is placed on footwork, body posturing, weapon control, flow-drills, and disarms.', ARRAY[]::TEXT[], NULL),
    ('SPH-I 145', 'INTRO TO THE MARTIAL ARTS', '4353', 'Class Status', 'MW Monday, Wednesday 1:55 PM–2:45 PM', 'GF 199', 'Michael Durisen', 3, NULL, 'Lecture', '2', 'BILL GARRETT FIELDHOUSE', ARRAY[]::TEXT[], 'A basic introduction to the martial arts, including karate, hapkido, jujitsu, judo, aikido, kung-fu, boxing, and wrestling. Students will learn the core concepts of each art, and thus gain a working understanding of what the martial arts are all about, and the differences between them.', ARRAY[]::TEXT[], NULL),
    ('SPH-I 146', 'JEET KUNE DO CONCEPTS', '4229', 'Class Status', 'MW Monday, Wednesday 12:45 PM–1:35 PM', 'GF 199', 'Michael Durisen', 2, NULL, 'Activity', '1', 'BILL GARRETT FIELDHOUSE', ARRAY[]::TEXT[], 'Instruction in the basic concepts of Jeet Kune Do philosophy and techniques derived from Jun-fan Kickboxing and Wing-chun Kung Fu. Students should achieve rudimentary technical skill in the art of Jun-fan Kickboxing and Wing-chun and learn the philosophy and training concepts of Jeet Kune Do.', ARRAY[]::TEXT[], NULL),
    ('SPH-I 150', 'TAE KWON DO', '11502', 'Class Status', 'TuTh Tuesday, Thursday 3:10 PM–4:00 PM', 'GF 199', 'Brian Wheeler', 12, NULL, 'Activity', '1', 'BILL GARRETT FIELDHOUSE', ARRAY[]::TEXT[], 'Beginning instruction in techniques of blocking, kicking, striking, punching, limited free fighting, and self-defense. Students should achieve technical level of yellow belt. Karate uniform required.', ARRAY[]::TEXT[], NULL),
