    ('SPH-I 240', 'INTERMEDIATE BRAZILIAN JU-JITSU', '10141', 'Class Status', 'TuTh Tuesday, Thursday 11:35 AM–12:25 PM', 'GF 199', 'Gregory Lucas', 10, NULL, 'Activity', '1', 'BILL GARRETT FIELDHOUSE', ARRAY[]::TEXT[], 'Instruction in intermediate ground fighting techniques, throwing, joint locks, chokes, and some self-defense derived from Caique Brazilian Ju-Jitsu. Students should achieve intermediate technical skill and learn the philosophy and concepts used in ground-fighting martial art practice as well as applying these concepts to competitive ground fighting. Focus is placed on body posturing, position control, flow-drills and submission techniques for competition. Students should achieve Yellow Belt proficiency.', ARRAY[]::TEXT[], NULL),
    ('SPH-I 272', 'SCUBA KNOWLEDGE DEVELOPMENT', '3171', 'Class Status', NULL, 'WB WEB', 'Matthew Maus', 34, NULL, 'Lecture', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Scuba Knowledgement Development through web based and CD-Rom sessions for International Scuba certification. Completes all Professional Assocation of Diving Instructors (PADI) open water certification knowledge sessions and examinations.', ARRAY[]::TEXT[], NULL),
    ('SPH-I 272', 'SCUBA KNOWLEDGE DEVELOPMENT', '8287', 'Class Status', NULL, 'WB WEB', 'Matthew Maus', 36, NULL, 'Lecture', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Scuba Knowledgement Development through web based and CD-Rom sessions for International Scuba certification. Completes all Professional Assocation of Diving Instructors (PADI) open water certification knowledge sessions and examinations.', ARRAY[]::TEXT[], NULL),
    ('SPH-I 281', 'TENNIS - INTERMEDIATE', '10144', 'Class Status', 'MWF Monday, Wednesday, Friday 9:00 AM–10:00 AM', 'HD TBA', 'Christopher Chopra', 3, NULL, 'Activity', '1–2', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Instruction in spin service, volley, lob, and advanced drive placement. Emphasis on singles and doubles playing strategies.', ARRAY[]::TEXT[], NULL),
    ('SPH-I 281', 'TENNIS - INTERMEDIATE', '10145', 'Class Status', 'MWF Monday, Wednesday, Friday 9:50 AM–10:50 AM', 'HD TBA', 'Christopher Chopra', 2, NULL, 'Activity', '1–2', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Instruction in spin service, volley, lob, and advanced drive placement. Emphasis on singles and doubles playing strategies.', ARRAY[]::TEXT[], NULL),
    ('SPH-I 340', 'ADVANCED BRAZILIAN JU-JITSU', '11567', 'Class Status', 'TuTh Tuesday, Thursday 10:25 AM–11:15 AM', 'GF 199', 'Gregory Lucas', 7, NULL, 'Activity', '1', 'BILL GARRETT FIELDHOUSE', ARRAY[]::TEXT[], 'Instruction in advanced ground fighting techniques, throwing, joint locks, chokes, and some self-defense derived from Caique Brazilian Ju-Jitsu. Students should achieve advanced technical skill and be well practiced in the philosophy and concepts used in ground-fighting martial art practice as well as applying these concepts to competitive ground fighting. Focus is placed on position control, flow, and submission technique. Competition is stressed. Students should achieve Advanced Yellow Belt proficiency.', ARRAY[]::TEXT[], NULL),
    ('SPH-I 350', 'ADVANCED TAE KWON DO', '30105', 'Class Status', 'MW Monday, Wednesday 4:10 PM–5:00 PM', 'GF 199', 'James Thomas', 9, NULL, 'Activity', '1', 'BILL GARRETT FIELDHOUSE', ARRAY[]::TEXT[], 'Designed to give students an increased understanding and an appreciation of the art of karate and taekwondo. Content emphasis involves advanced applications of basic taekwondo techniques, one-step sparring, forms, and introduction to free fighting. Students should achieve a technical level of a blue belt in taekwondo (Korean karate) by midterm and brown belt by finals. Karate uniform required.', ARRAY[]::TEXT[], NULL),
    ('SPH-I 370', 'SCUBA CERTIFICATION', '8968', 'Class Status', 'M Monday 9:10 AM–10:00 AM', 'PY 115', 'Charles Beeker', 3, 'Lecture', 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'This course focuses on the development of basic SCUBA diving skills within a confined water environment in accordance to standards set forth by the Professional Association of Dive Instructors (PADI). Open Water Certification dives may be completed with IU or any PADI facility (Additional fees may be required)', ARRAY[]::TEXT[], NULL),
