    ('SPH-I 445', 'INDEPENDENT STUDY IN THE MARTIAL ARTS', '4231', 'Class Status', NULL, NULL, 'Patrick Kelly', 48, NULL, 'Independent Study', '1', NULL, ARRAY[]::TEXT[], 'This course allows advanced students in the IU Martial Arts Program to continue their training and personal development in preparation for their instructor''s certification in their respective art. Students in this course will meet with the IU Martial Arts Program Coordinator to discuss the personal and professional goals they have set for the semester. Focus will be placed upon teaching pedagogy, independent exploration into cross training with martial arts outside their area of expertise, and training regiment to ensure a prepared and well-rounded student. Completion of this course should coincide with the student''s achievement of instructor certification.', ARRAY[]::TEXT[], NULL),
    ('SPH-I 470', 'DIVER SAFETY & RESCUE', '5844', 'Class Status', 'M Monday 3:10 PM–4:00 PM', 'BH 233', 'Samuel Haskell', 6, 'Lecture', 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Advanced aspects of diving physics, physiology, diver stress, and rescue. Completes national training standards for certification.', ARRAY[]::TEXT[], NULL),
    ('SPH-I 470', 'DIVER SAFETY & RESCUE', '5845', 'Class Status', NULL, NULL, 'Samuel Haskell', 2, 'Laboratory', 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Advanced aspects of diving physics, physiology, diver stress, and rescue. Completes national training standards for certification.', ARRAY[]::TEXT[], NULL),
    ('SPH-I 470', 'DIVER SAFETY & RESCUE', '5846', 'Class Status', NULL, NULL, 'Samuel Haskell', 2, 'Laboratory', 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Advanced aspects of diving physics, physiology, diver stress, and rescue. Completes national training standards for certification.', ARRAY[]::TEXT[], NULL),
    ('SPH-I 470', 'DIVER SAFETY & RESCUE', '5847', 'Class Status', NULL, NULL, 'Samuel Haskell', 2, 'Laboratory', 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Advanced aspects of diving physics, physiology, diver stress, and rescue. Completes national training standards for certification.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 150', 'INTRODUCTION TO KINESIOLOGY AND PUBLIC HEALTH', '11091', 'Class Status', 'Th Thursday 9:35 AM–10:50 AM', 'FA 015', 'Donetta Cothran', 31, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Introductory course designed to provide students an overview of both the foundations of public health and kinesiology. Specifically this course will introduce students to the five core knowledge areas of public health including epidemiology, biostatistics, environmental health science, health administration, and social and behavioral sciences as well as the core areas of kinesiology including history of physical activity, exercise physiology, biomechanics and motor control. The connection between the scholarship of kinesiology and goals of public health will be emphasized', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPH-K 150', 'INTRODUCTION TO KINESIOLOGY AND PUBLIC HEALTH', '6221', 'Closed', 'Tu Tuesday 9:35 AM–10:50 AM', 'FA 015', 'Donetta Cothran', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Introductory course designed to provide students an overview of both the foundations of public health and kinesiology. Specifically this course will introduce students to the five core knowledge areas of public health including epidemiology, biostatistics, environmental health science, health administration, and social and behavioral sciences as well as the core areas of kinesiology including history of physical activity, exercise physiology, biomechanics and motor control. The connection between the scholarship of kinesiology and goals of public health will be emphasized', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPH-K 199', 'CAREERS IN HELPING PROFESSIONS', '13320', 'Class Status', 'MW Monday, Wednesday 10:10 AM–11:00 AM', 'BH 105', 'June Coleman', 2, NULL, 'Lecture', '2', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Helping professions are career paths that nurture growth in one or more domains of wellness, including disciplines such as medicine, nursing, allied health, social work, education, fitness, and life coaching. Students will learn how their values, interests, personality, and skills align with career options in the helping professions. Focus is on early career development and navigating career resources.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 199', 'CAREERS IN HELPING PROFESSIONS', '9655', 'Closed', NULL, 'WB WEB', 'Kristine Nielsen', 0, NULL, 'Lecture', '2', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Helping professions are career paths that nurture growth in one or more domains of wellness, including disciplines such as medicine, nursing, allied health, social work, education, fitness, and life coaching. Students will learn how their values, interests, personality, and skills align with career options in the helping professions. Focus is on early career development and navigating career resources.', ARRAY[]::TEXT[], NULL),
