    ('SPH-K 200', 'COMPUTER TECHNOLOGY IN PUBLIC HEALTH', '5721', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'GY 2053', 'Margaret Lion', 7, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'A hands-on introduction to the use of computers as problem solving, management, and communication tools. Students create personalized projects while developing proficiency in word processing, spreadsheet, database, presentation, media editing, podcasting, and website development.', ARRAY['Class uses IU eTexts'], NULL),
