    ('SPH-K 205', 'STRUCTURAL KINESIOLOGY', '5729', 'Closed', 'W Wednesday 11:30 AM–1:25 PM', 'PH 019', 'Christopher Thompson', 0, 'Laboratory', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Overview of basic human body structures and functions appropriate for beginning students in physical education. Fundamental concepts concerning the interaction of biological and mechanical aspects of the musculoskeletal and neuromuscular structures. Emphasis on practical application to study and teaching of skilled human movement.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('SPH-K 205', 'STRUCTURAL KINESIOLOGY', '5730', 'Closed', 'Th Thursday 5:20 PM–7:15 PM', 'PH 019', 'Christopher Thompson', 0, 'Laboratory', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Overview of basic human body structures and functions appropriate for beginning students in physical education. Fundamental concepts concerning the interaction of biological and mechanical aspects of the musculoskeletal and neuromuscular structures. Emphasis on practical application to study and teaching of skilled human movement.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('SPH-K 212', 'INTRO TO EXERCISE SCIENCE', '8256', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 310', 'Elizabeth Mooradian', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'An introduction to the science of exercise and human movement. Special topics in exercise physiology, sport biomechanics, sports medicine, and motor integration.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('SPH-K 212', 'INTRO TO EXERCISE SCIENCE', '8962', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'ED 1120', 'Elizabeth Mooradian', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'An introduction to the science of exercise and human movement. Special topics in exercise physiology, sport biomechanics, sports medicine, and motor integration.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('SPH-K 216', 'FOUNDATIONS OF PHYSICAL ACTIVITY AND PUBLIC HEALTH', '5731', 'Closed', 'Tu Tuesday 3:55 PM–5:10 PM', 'GY 1050', 'Rachel Ryder', 0, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'This course is designed to introduce the field of physical activity and public health and provide students with foundational principles of both public health science and exercise science to promote improved health through physical activity.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-K 250', 'INTRODUCTORY SPECIAL TOPICS IN KINESIOLOGY', '30076', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'SY 210', 'Blair Johnson', 0, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'A variable-topic course dealing with foundational and/or current topics not ordinarily covered in the kinesiology curriculum. No prior experience or knowledge of kinesiology assumed. Specific topics vary by course offering. Repeatable for credit with different special topic.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 250', 'INTRODUCTORY SPECIAL TOPICS IN KINESIOLOGY', '33817', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 134', 'Zachary Schlader', 0, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'A variable-topic course dealing with foundational and/or current topics not ordinarily covered in the kinesiology curriculum. No prior experience or knowledge of kinesiology assumed. Specific topics vary by course offering. Repeatable for credit with different special topic.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 280', 'BASIC PREV&CARE OF ATHL INJ', '10818', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'WH 111', 'Joel Langemaat', 1, NULL, 'Lecture', '2', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Course will focus on basic principles of prevention recognition and management of sport-related injuries.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-K 280', 'BASIC PREV&CARE OF ATHL INJ', '11532', 'Closed', 'MW Monday, Wednesday 12:45 PM–1:35 PM', 'WH 111', 'Joseph Lueken', 0, NULL, 'Lecture', '2', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Course will focus on basic principles of prevention recognition and management of sport-related injuries.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-K 290', 'MOVMT EXP PRESCH & ELEM CHLD', '9751', 'Class Status', 'M Monday 12:45 PM–1:35 PM', 'HD TBA', 'Ann Huntoon', 3, NULL, 'Lecture', '2', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-K 290', 'MOVMT EXP PRESCH & ELEM CHLD', '9752', 'Closed', 'Tu Tuesday 12:45 PM–1:35 PM', 'HD TBA', 'Ann Huntoon', 0, NULL, 'Lecture', '2', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-K 301', 'PROFESSIONAL AND CAREER PREPARATION', '3488', 'Class Status', NULL, 'WB WEB', 'Kimberly Ecenbarger', 1, NULL, 'Lecture', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Whether preparing for graduate school or pursing a full-time position, this course will empower you to take your next step more prepared and confident. Classroom discussion, activities, and assignments tie directly to your career success. This course is most suitable for junior or senior -level students. You will learn how to: - Navigate the graduate school application process or begin your full-time job search - Customize application materials including resume, cover letter/personal statement, and references - Convey skills and articulate qualifications during an interview - Evaluate programs and offers and accept, decline, or negotiate professionally - Prepare for a smooth transition from undergraduate education to your next destination', ARRAY[]::TEXT[], NULL),
    ('SPH-K 305', 'MECHANICAL BASIS OF HUMAN MOVEMENT', '8963', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'EP 257', 'Brian Moscicki', 111, NULL, 'Lecture', '3', 'ERNIE PYLE HALL', ARRAY[]::TEXT[], 'This course examines how structures interact to produce smooth, coordinated movement. Focus is placed on how internal and external forces affect tissues and cause human movement. How the musculoskeletal and neuromuscular systems interact to achieve movement tasks will be examined.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 316', 'THEORIES OF ADV CONDITIONING', '2001', 'Class Status', 'MWF Monday, Wednesday, Friday 8:00 AM–8:50 AM', 'BH 227', 'Braden Singleton', 19, NULL, 'Lecture', '2', 'BALLANTINE HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-K 319', 'PHYSICAL ACTIVITY/EXERCISE LEADERSHIP', '11531', 'Class Status', 'MW Monday, Wednesday 1:55 PM–2:45 PM', 'PH C100 GF 199', 'Rachel Ryder, Elaine Deppe', 20, NULL, 'Lecture', '3', 'SCHOOL OF PUBLIC HEALTH, BILL GARRETT FIELDHOUSE', ARRAY[]::TEXT[], 'To apply the CDC and ACSM exercise recommendations in fitness leadership for both apparently healthy individuals and those with controlled diseases. This includes the creation, presentation, and evaluation of exercise leadership and programming, utilizing a research-based approach to physical activity and exercise leadership.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-K 327', 'BEHAVIORAL ASPECTS OF PHYSICAL ACTIVITY AND EXERCISE', '8343', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'WB WEB', 'Kyle Kercher', 5, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Provides students with practical experience in physical activity/exercise coaching utilizing behavior models and theories and physical activity/fitness best practices. Students examine physical activity theories and motivational techniques needed to assist participants with physical activity perspectives/interventions. Students apply behavioral techniques to actual clients and evaluate the outcomes of their efforts.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 335', 'THEORIES CONDITION FOR COACHNG', '5734', 'Class Status', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'LH 130', 'Jayd Grossman', 1, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'A practical application of conditioning and physical training theory of coaching and high level fitness. The class utilizes physiological principles of conditioning to prepare athletes for optimal performance. Discusses various types of training and organization of workouts for endurance, speed, and strength.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 350', 'INTERMEDIATE SPECIAL TOPICS IN KINESIOLOGY', '36183', 'Closed', 'MWF Monday, Wednesday, Friday 1:10 PM–2:00 PM', 'ED 1255', 'John Shea', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'A variable-topic course focused on special topics not ordinarily covered in the kinesiology curriculum. Intermediate level experience with or knowledge of kinesiology assumed. Repeatable for credit.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 350', 'INTERMEDIATE SPECIAL TOPICS IN KINESIOLOGY', '12040', 'Closed', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'BH 306', 'Jeff Huntoon', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'A variable-topic course focused on special topics not ordinarily covered in the kinesiology curriculum. Intermediate level experience with or knowledge of kinesiology assumed. Repeatable for credit.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 350', 'INTERMEDIATE SPECIAL TOPICS IN KINESIOLOGY', '32271', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'EP 256', 'Jeff Huntoon', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'A variable-topic course focused on special topics not ordinarily covered in the kinesiology curriculum. Intermediate level experience with or knowledge of kinesiology assumed. Repeatable for credit.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 385', 'PRACTICUM IN ADAPTED PHYSICAL ACTIVITY', '5749', 'Class Status', NULL, NULL, 'Georgia Frey', 11, NULL, 'Independent Study', '1–2', NULL, ARRAY[]::TEXT[], 'A practical learning experience in adapted physical activity with differently abled children and youth.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 391', 'BIOMECHANICS', '5738', 'Closed', 'MW Monday, Wednesday 9:10 AM–10:00 AM', 'WH 120', 'Brian Moscicki', 0, 'Lecture', 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'An introduction to the mechanics of human motion. Includes linear and angular kinematics and kinetics in the context of human motion; mechanics of fluids; mechanics of muscles; analysis of selected sports activities.', ARRAY['Class uses IU eTexts'], NULL),
