    ('SPH-K 391', 'BIOMECHANICS', '5744', 'Closed', 'Th Thursday 12:40 PM–2:30 PM', 'PH 019', 'Brian Moscicki', 0, 'Laboratory', 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'An introduction to the mechanics of human motion. Includes linear and angular kinematics and kinetics in the context of human motion; mechanics of fluids; mechanics of muscles; analysis of selected sports activities.', ARRAY['Class uses IU eTexts'], NULL),
