    ('SPH-K 391', 'BIOMECHANICS', '5746', 'Closed', 'F Friday 10:20 AM–12:10 PM', 'PH 019', 'Brian Moscicki', 0, 'Laboratory', 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'An introduction to the mechanics of human motion. Includes linear and angular kinematics and kinetics in the context of human motion; mechanics of fluids; mechanics of muscles; analysis of selected sports activities.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-K 391', 'BIOMECHANICS', '32694', 'Closed', 'W Wednesday 3:00 PM–4:50 PM', 'PH 019', 'Brian Moscicki', 0, 'Laboratory', 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'An introduction to the mechanics of human motion. Includes linear and angular kinematics and kinetics in the context of human motion; mechanics of fluids; mechanics of muscles; analysis of selected sports activities.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-K 395', 'FITNESS SPECIALIST PRACTICUM', '4338', 'Class Status', 'W Wednesday 4:30 PM–7:30 PM', 'SB 140', 'Ann Huntoon', 16, NULL, 'Practicum', '2', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'This is a practice course and is critical to your ability to be effective at program design and exercise leadership; specifically with youth who are considered overweight and or obese. This is an applied course from many perspectives: content based, performance based and process based. In other words, you will be expected to use your brain and your bodies to complete this course. You will gain insight and experience thru the above stated objectives as you demonstrate the ability to create safe, effective program design based on individual client needs and goals. In addition, you will also be exposed to a variety of programming options which should provide you with tools for personalizing and individualizing exercise programs based on the client''s personal profile (medical history, assessment and goals).', ARRAY[]::TEXT[], NULL),
    ('SPH-K 398', 'ADAPTED PHYSICAL ACTIVITY', '5747', 'Closed', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'SY 006', 'Georgia Frey', 0, 'Lecture', 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Study of conditions that require physical activity programs to be adapted to the special needs of individuals. Principles and practices in the application of exercise and activities for persons with specific disabling conditions.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 398', 'ADAPTED PHYSICAL ACTIVITY', '5748', 'Closed', 'Th Thursday 5:00 PM–7:00 PM', 'PH 169', 'Georgia Frey', 0, 'Laboratory', 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Study of conditions that require physical activity programs to be adapted to the special needs of individuals. Principles and practices in the application of exercise and activities for persons with specific disabling conditions.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 398', 'ADAPTED PHYSICAL ACTIVITY', '9428', 'Closed', 'Th Thursday 5:00 PM–7:00 PM', 'PH 169', 'Georgia Frey', 0, 'Laboratory', 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Study of conditions that require physical activity programs to be adapted to the special needs of individuals. Principles and practices in the application of exercise and activities for persons with specific disabling conditions.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 405', 'EXERCISE AND SPORT PSYCHOLOGY', '5750', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'ED 1120', 'John Raglin', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Having knowledge of the behavioral factors which contribute to participation in sport and exercise activities is necessary for those interested in professions within this context. This three credit course will involve a broad survey of the field of sport psychology and exercise and health behavior. Although a major thrust of American sport psychology involves the application of techniques intended to enhance athletic performance, this course will also cover subjects in the area of exercise and health behavior, such as the influence of exercise on mental health, and public health policy in regards to adherence to physical activity. Topics such as the psychology of coaching in sport and exercise/health programming will be evaluated in order to determine best practices for application to solve contemporary issues such as the growing concern of stress and the associated health issues within contemporary environments, such as the workplace. Comprehension of this material will be synthesized into possible interventions which promote prevention and positive lifestyle behaviors. Traditional topics in sport psychology will also be discussed, such as the relationship between anxiety and athletic performance and the purported benefits of anxiety reduction techniques But because there is a widespread lack of empirical evidence to support their use, there will be a strong emphasis on important issues in sport psychology, as well as exercise and health behavior research; drawing attention to credibility, professionalism and the utility of this field. Ultimately, the material covered in this course will improve the knowledge of sport and health professionals in regards to these issues. This will better able those in these professions (and the public) to discriminate in judging the value and usefulness of information and applications in sport psychology and exercise and health behavior.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 405', 'EXERCISE AND SPORT PSYCHOLOGY', '9427', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'ED 1120', 'John Raglin', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Having knowledge of the behavioral factors which contribute to participation in sport and exercise activities is necessary for those interested in professions within this context. This three credit course will involve a broad survey of the field of sport psychology and exercise and health behavior. Although a major thrust of American sport psychology involves the application of techniques intended to enhance athletic performance, this course will also cover subjects in the area of exercise and health behavior, such as the influence of exercise on mental health, and public health policy in regards to adherence to physical activity. Topics such as the psychology of coaching in sport and exercise/health programming will be evaluated in order to determine best practices for application to solve contemporary issues such as the growing concern of stress and the associated health issues within contemporary environments, such as the workplace. Comprehension of this material will be synthesized into possible interventions which promote prevention and positive lifestyle behaviors. Traditional topics in sport psychology will also be discussed, such as the relationship between anxiety and athletic performance and the purported benefits of anxiety reduction techniques But because there is a widespread lack of empirical evidence to support their use, there will be a strong emphasis on important issues in sport psychology, as well as exercise and health behavior research; drawing attention to credibility, professionalism and the utility of this field. Ultimately, the material covered in this course will improve the knowledge of sport and health professionals in regards to these issues. This will better able those in these professions (and the public) to discriminate in judging the value and usefulness of information and applications in sport psychology and exercise and health behavior.', ARRAY[]::TEXT[], NULL),
