    ('SPH-K 409', 'BASIC PHYSIOLOGY OF EXERCISE', '12453', 'Closed', 'M Monday 12:40 PM–2:30 PM', 'PH 017', 'Timothy Mickleborough', 0, 'Laboratory', 'Lecture', '3', 'MYERS HALL', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-K 412', 'EXERCISE IN HEALTH AND DISEASE', '9162', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'EP 257', 'Stephen Carter', 2, NULL, 'Lecture', '3', 'ERNIE PYLE HALL', ARRAY[]::TEXT[], 'Designed for students preparing for careers in medical professions: In-depth scientific study of etiology, pathophysiology, and mechanisms of exercise intervention for chronic diseases: including, not limited to, atherosclerotic cardiovascular disease, hypertension, metabolic syndrome, diabetes (including complications), hyperlipidemia, obesity, cancer, and chronic obstructive lung disease.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 416', 'PHYSICAL ACTIVITY/FITNESS ADMINISTRATION', '5758', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'LH 023', 'Christopher Arterberry', 18, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Provide research and content information for administration of Physical Activity (PA)/Fitness business practices. Learn trends and best program practices for PA/Fitness businesses. Discuss contemporary issues and participate in group problem solving activities for a business. Integrate knowledge through researching a specific business of interest using PA/Fitness Administrative best practices.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-K 417', 'PHYSICAL ACTIVITY AND DISEASE', '10743', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'WH 104', 'Blair Johnson', 11, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Provides an overview of the role of physical activity in the prevention of disease and disability. The causes of common diseases, physiological impact, and treatment side effects of common diseases will be discussed to enable effective exercise prescription within special populations.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 419', 'FITNESS TESTING & INTERPRETATN', '5759', 'Class Status', 'W Wednesday 10:25 AM–11:15 AM', 'TE F104', 'Elizabeth Mooradian, Rachel Ryder', 9, 'Lecture', 'Lecture', '3', 'TETER QUAD', ARRAY[]::TEXT[], 'Provides practical experience with various fitness testing protocols, basic exercise prescription, and interpretation of fitness data.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 419', 'FITNESS TESTING & INTERPRETATN', '5760', 'Class Status', 'F Friday 8:00 AM–9:50 AM', 'PH 017', 'Rachel Ryder', 9, 'Laboratory', 'Lecture', '3', 'TETER QUAD', ARRAY[]::TEXT[], 'Provides practical experience with various fitness testing protocols, basic exercise prescription, and interpretation of fitness data.', ARRAY[]::TEXT[], NULL),
