    ('SPH-K 450', 'ADVANCED SPECIAL TOPICS IN KINESIOLOGY', '13308', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'SY 037', 'Kyle Kercher', 10, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'A variable-topic course dealing with advanced and/or current topics not ordinarily covered in kinesiology. Foundational experience or knowledge of kinesiology assumed.', ARRAY[]::TEXT[], NULL),
