    ('SPH-K 450', 'ADVANCED SPECIAL TOPICS IN KINESIOLOGY', '12575', 'Closed', NULL, 'WB WEB', 'Katie Palano', 0, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'A variable-topic course dealing with advanced and/or current topics not ordinarily covered in kinesiology. Foundational experience or knowledge of kinesiology assumed.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 452', 'MOTOR LEARNING', '5764', 'Class Status', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'WH 101', 'Rachel Ryder', 7, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'An examination of factors that affect the acquisition and performance of motor skills. Topics include perception, psychomotor learning, practice methods, and theories of neuromuscular integration.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 455', 'PRACTICUM IN COACHING', '3134', 'Class Status', NULL, NULL, 'Ann Huntoon', 20, NULL, 'Practicum', '2', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-K 485', 'PRACTICUM IN KINESIOLOGY AND ATHLETICS', '5765', 'Class Status', NULL, NULL, 'Patrick Kelly', 36, NULL, 'Independent Study', '1', NULL, ARRAY[]::TEXT[], 'Instructor permission required. A practical learning experience in teaching and/or coaching under guidance of faculty and supervisor.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 486', 'FIELD EXPERIENCE IN FITNESS AND WELLNESS', '10831', 'Class Status', NULL, NULL, 'Rachel Ryder', 4, NULL, 'Internship', '1–8', NULL, ARRAY[]::TEXT[], 'BSPH students in the Fitness and Wellness degree develop their public health skills through professional experiences in public health settings under the supervision of IU SPH-K faculty and facilitation of preceptors. The Faculty Coordinator and the preceptors conduct regular evaluations, provide written progress reports, and facilitate the development of the Major Independent Project.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 490', 'MOTOR DEVELOPMENT & LEARNING', '14248', 'Closed', NULL, 'WB WEB', 'Melissa Pangelinan', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Motor learning and development principles throughout the life span. Emphasis on observing and analyzing characteristic movement behavior, motor learning, and motor performance, with application to developmentally appropriate movement experiences.', ARRAY[]::TEXT[], NULL),
