    ('SPH-K 496', 'LABORATORY ASSISTING OR FIELD EXPERIENCE IN KINESIOLOGY', '10558', 'Class Status', 'TuTh Tuesday, Thursday 9:10 AM–10:50 AM', 'HD TBA', 'Tammy Nichols', 3, NULL, 'Independent Study', '1', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Student will assist in either an ongoing or a new research project, or obtain some other field experience, under the guidance of a faculty sponsor.', ARRAY[]::TEXT[], NULL),
