    ('SPH-K 497', 'INTERNSHIP IN EXERCISE SCIENCE', '3309', 'Class Status', NULL, NULL, 'Ann Huntoon', 89, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-K 506', 'COMPUTER APPL IN KINESIOLOGY', '1991', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'GY 2053', 'Margaret Lion', 4, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-K 520', 'MATLAB FOR DATA ANALYSIS', '35507', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WB WEB', 'Melissa Pangelinan', 6, NULL, 'Methods Course', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Principles of programming in general and MATLAB in particular will be covered at a level appropriate for novices. The focus will be on writing programs to organize, structure, and analyze types of data common in behavioral and physiological research. Challenges and strategies related to research data will be emphasized.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 525', 'PSYCH FOUND OF EXERCISE/SPORT', '5858', 'Class Status', 'Tu Tuesday 3:55 PM–6:25 PM', 'BH 233', 'John Raglin', 7, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course cover topics concerning various psychological aspects of sport performance. When applicable, psychological research will be integrated with findings from other areas of exercise science such as exercise physiology. Issues in the area of exercise and mental health will also be addressed, including research on recreational exercisers.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 535', 'PHYSIOL BASIS OF HUMAN PERF', '5766', 'Class Status', 'MW Monday, Wednesday 12:45 PM–1:35 PM', 'BH 241', 'Timothy Mickleborough', 8, 'Lecture', 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-K 535', 'PHYSIOL BASIS OF HUMAN PERF', '5767', 'Class Status', 'F Friday 8:00 AM–10:00 AM', 'PH 019', 'Timothy Mickleborough', 8, 'Laboratory', 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-K 542', 'NEUROMUSCULAR CNTRL OF MOVEMT', '5768', 'Class Status', 'MW Monday, Wednesday 10:10 AM–11:25 AM', 'PH 017', 'David Koceja', 3, NULL, 'Lecture', '3', 'SCHOOL OF PUBLIC HEALTH', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-K 543', 'CORTICAL CONTROL HUM MOVEMENT', '29479', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GY 1042', 'Hannah Block', 6, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'This multidisciplinary course is designed to provide students with an understanding of the neuroanatomical, neurophysiological, and neurobehavioral foundations of voluntary human movement. Seminar-based lectures will emphasize the structure and functional involvement of cortical and subcortical regions associated with purposeful action (e.g., goal-directed reaching, speech, and locomotion). In addition, case descriptions will be discussed to provide students with a link between neuropathogenesis and specific motor deficits.', ARRAY[]::TEXT[], NULL),
    ('SPH-K 550', 'SPECIAL TOPICS IN KINESIOLOGY: (TITLE)', '5860', 'Class Status', NULL, NULL, 'Charles Beeker', 1, NULL, 'Lecture', '1–3', 'SYCAMORE HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
