    ('SPH-L 102', 'PERSONAL LEADERSHIP DEVELOPMENT', '7603', 'Class Status', NULL, NULL, 'Deborah Getz', 10, NULL, 'Lecture', '1', NULL, ARRAY[]::TEXT[], 'An interactive online course blended with four one hour structured classroom meetings. Provides students with opportunities to learn and apply leadership skills gained through participation in organizations, athletic teams, or clubs. Will develop own personal leadership plan to initiate intentional leadership involvement. Topics include fellowship, time management, and teamwork.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 211', 'INTRO TO SPORT MANAGEMENT', '6222', 'Class Status', NULL, 'WB WEB', 'Joshua Shelton', 7, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'An examination of the broad spectrum of career opportunities available in the sport management profession. Special emphasis on career planning, sport management terminology, and an overview of specific skills and courses required for professional preparation in sport management.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-M 211', 'INTRO TO SPORT MANAGEMENT', '8089', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'WH 101', 'Joshua Shelton', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'An examination of the broad spectrum of career opportunities available in the sport management profession. Special emphasis on career planning, sport management terminology, and an overview of specific skills and courses required for professional preparation in sport management.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-M 304', 'SPORT INDUSTRY STUDIES', '15047', 'Closed', NULL, 'WB WEB', 'Jiayao Qi', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'A topical course in sport studies and emerging trends. Through lectures, group projects, experiential learning, and study of the current and future state of various elements of sport marketing, sport management, and sport communication, students will gain a greater understanding of the challenges facing today''s sport professionals. Topics will change semester by semester.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 304', 'SPORT INDUSTRY STUDIES', '32775', 'Closed', NULL, 'WB WEB', 'Wooyoung (William) Jang', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'A topical course in sport studies and emerging trends. Through lectures, group projects, experiential learning, and study of the current and future state of various elements of sport marketing, sport management, and sport communication, students will gain a greater understanding of the challenges facing today''s sport professionals. Topics will change semester by semester.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 310', 'SPORT ANALYTICS', '32692', 'Class Status', NULL, 'WB WEB', 'Wooyoung (William) Jang', 2, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course focuses on exploring, identifying, and solving problems within the sport industry using data. In the data-focused analytics courses, students learn how to make data-driven decisions by understanding the analytic approaches in data analysis, how to interpret data, and computational skills.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 314', 'E-SPORTS MANAGEMENT AND MARKETING', '15048', 'Closed', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'WH 120', 'Wooyoung (William) Jang', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course provides students with a study of the concept of eSports, eSports industry, the eSports organizations'' current standing, and marketing/management strategies. Thus, it leads students developing the understanding of what is eSports and how eSports organization develop and apply marketing/management strategies.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 318', 'MANAGING THE SPORT ENTERPRISE', '2002', 'Class Status', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'WH 101', 'Cassandra Coble', 1, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'An introduction to management theory as it relates to sport delivery systems. Includes the study of organizational structure, leadership, motivation, ethics, and decision making. Application of theoretical material to managerial function of sport delivery organizations.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 318', 'MANAGING THE SPORT ENTERPRISE', '15119', 'Closed', NULL, 'WB WEB', 'Cassandra Coble', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'An introduction to management theory as it relates to sport delivery systems. Includes the study of organizational structure, leadership, motivation, ethics, and decision making. Application of theoretical material to managerial function of sport delivery organizations.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 328', 'ISSUES IN INTERCOLLEGIATE ATHLETICS', '3585', 'Closed', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'MO 007', 'Jim Evans', 0, NULL, 'Lecture', '3', 'MORRISON HALL', ARRAY[]::TEXT[], 'Examination of current issues in intercollegiate sport in America. Presents the historical foundation of current issues and solutions, and examines current positions and arguments.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-M 333', 'SPORT IN AMERICA: HIST PERSPECTV', '5733', 'Closed', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WH 101', 'Robert Whitaker', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Study of the evolution of sport in the United States within the larger context of historical developments in society; women''s sport experiences in relation to the development of sport; examination of sport as a reflection of American culture from the founding of the colonies to the present.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 333', 'SPORT IN AMERICA: HIST PERSPECTV', '15120', 'Closed', NULL, 'WB WEB', 'Robert Whitaker', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Study of the evolution of sport in the United States within the larger context of historical developments in society; women''s sport experiences in relation to the development of sport; examination of sport as a reflection of American culture from the founding of the colonies to the present.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 382', 'SPORT IN AMERICAN SOCIETY', '11086', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'EP 257', 'Jim Evans', 0, NULL, 'Lecture', '3', 'ERNIE PYLE HALL', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-M 382', 'SPORT IN AMERICAN SOCIETY', '15121', 'Closed', NULL, 'WB WEB', 'Cassandra Coble', 0, NULL, 'Lecture', '3', 'ERNIE PYLE HALL', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-M 404', 'COLLOQUIUM IN SPORT MANAGEMENT', '32763', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WH 003', 'Diane Cassimire', 1, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'A sport management colloquium that is focused on experiential learning, content projects, and study of the current and future state of various elements of sport marketing, sport management, sport communication, and sport administration. Through hands-on projects and interactions with industry professionals, students will gain a greater understanding of the challenges facing today''s sport administration professionals. Colloquium topics will change by semester.', ARRAY['Class uses IU eTexts'], NULL),
