    ('SPH-M 415', 'SPORT PROMOTIONS & PUBL RELNS', '8469', 'Closed', 'MWF Monday, Wednesday, Friday 3:10 PM–4:00 PM', 'MY 130', 'Wooyoung (William) Jang', 0, NULL, 'Lecture', '3', 'MYERS HALL', ARRAY[]::TEXT[], 'An introduction to the theories and techniques of sport promotions, public relations, and fund-raising.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 418', 'SPORT MARKETING', '10349', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'WH 120', 'Jiho Kim', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Examination of the elements of the marketing mix as they pertain to the sport enterprise. Also includes the coverage of decision making and planning from the sport manager''s perspective and the impact of corporate sponsorship on the delivery of sport.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-M 418', 'SPORT MARKETING', '11414', 'Closed', 'TuTh Tuesday, Thursday 9:25 AM–10:40 AM', 'WB WEB', 'Antonio Williams', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Examination of the elements of the marketing mix as they pertain to the sport enterprise. Also includes the coverage of decision making and planning from the sport manager''s perspective and the impact of corporate sponsorship on the delivery of sport.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-M 423', 'FINANCIAL PRINCIPLES IN SPORT', '5762', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WH 101', 'Jiayao Qi', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-M 423', 'FINANCIAL PRINCIPLES IN SPORT', '9406', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WH 101', 'Jiayao Qi', 1, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-M 425', 'SPORT GOVERNANCE IN GLBL COMM', '6600', 'Closed', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'EP 257', 'Cassandra Coble', 0, NULL, 'Lecture', '3', 'ERNIE PYLE HALL', ARRAY[]::TEXT[], 'An introduction to the organization and governance of sport services and businesses. Examination of sport delivery systems in the United States including Olympic sport, sport through education systems, professional sport leagues, sport clubs, sport development, the coordination of sport in the United States. The class then examines U.S. sport in its international context.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 426', 'SALES MANAGEMENT IN SPORT', '5941', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'SM C141', 'Jonathan Benedek', 0, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'The application of sales strategies to the sport industry.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 426', 'SALES MANAGEMENT IN SPORT', '5763', 'Closed', NULL, 'WB WEB', 'Jonathan Benedek', 0, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'The application of sales strategies to the sport industry.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 428', 'STRAT MGMT IN SPORT INDUSTRY', '8946', 'Class Status', 'MW Monday, Wednesday 3:35 PM–4:50 PM', 'OP 111', 'Edward Renshler', 42, NULL, 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Strategic Management in Sport Industry has its emphasis on developing an understanding of how firms within the sport industry develop and apply competitive strategies.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 428', 'STRAT MGMT IN SPORT INDUSTRY', '36136', 'Closed', NULL, 'WB WEB', 'Edward Renshler', 0, NULL, 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Strategic Management in Sport Industry has its emphasis on developing an understanding of how firms within the sport industry develop and apply competitive strategies.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 495', 'PRACTICUM IN SPORTS STUDIES', '3308', 'Class Status', NULL, NULL, 'Jim Evans', 58, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Practical job-related learning experience in sport management or marketing under supervision of professional in area.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 495', 'PRACTICUM IN SPORTS STUDIES', '15049', 'Class Status', NULL, NULL, 'Joshua Shelton', 5, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Practical job-related learning experience in sport management or marketing under supervision of professional in area.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 497', 'INTERNSHIP IN SPORT MANAGEMENT', '3310', 'Class Status', NULL, NULL, 'Jim Evans', 54, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'A field learning experience for sport management majors.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 497', 'INTERNSHIP IN SPORT MANAGEMENT', '15050', 'Class Status', NULL, NULL, 'Joshua Shelton', 6, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'A field learning experience for sport management majors.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 511', 'LEGAL ISS IN SPORT ENVIRONMNT', '5861', 'Class Status', 'W Wednesday 8:00 AM–10:30 AM', 'GY 1032', 'Kristin Borrelli', 4, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-M 515', 'PRINCIPLES OF MANAGEMENT IN THE SPORT INDUSTRY', '37213', 'Class Status', NULL, NULL, 'Edward Renshler', 4, NULL, 'Readings', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course will introduce students to principles of management theory and application to contemporary sport management. Students will develop a general understanding of basic management principles and concepts in preparation for sport management careers working with and through others to achieve organizational objectives in a competitive, diverse, and dynamic environment.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 515', 'PRINCIPLES OF MANAGEMENT IN THE SPORT INDUSTRY', '36410', 'Closed', 'M Monday 7:00 PM–9:30 PM', 'BH 219', 'Edward Renshler', 0, NULL, 'Readings', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course will introduce students to principles of management theory and application to contemporary sport management. Students will develop a general understanding of basic management principles and concepts in preparation for sport management careers working with and through others to achieve organizational objectives in a competitive, diverse, and dynamic environment.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 518', 'GOVERNANCE IN SPORT MANAGEMENT', '8945', 'Class Status', 'Tu Tuesday 3:55 PM–6:25 PM', 'SY 0009', 'Jiayao Qi', 3, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'This course provides students with an advanced study of the governance of sport infrastructures, services, and businesses, nationally and internationally. It is no longer sufficient to merely understand the domestic side of sport management. Through multiple forms of assessment and contemporary case study, this course allows students to critically analyze issues in the global governance of sport.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 520', 'RESEARCH METHODS IN SPORT MANAGEMENT', '9844', 'Class Status', 'M Monday 9:00 AM–11:30 AM', 'WH 108', 'Jiayao Qi', 7, NULL, 'Methods Course', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course covers theories and concepts related to research methods and data analysis in sport management. Specific focus will be given to action components of the research process including: design and formulation, research strategies, methodological tools, and data analytical methods necessary to perform research.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 581', 'SALES & SERVICE MANAGEMENT IN SPORT', '5167', 'Class Status', 'Th Thursday 7:50 PM–10:20 PM', 'BH 012', 'Kevin Van Rooy', 6, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'The application of sales and service management strategies to the sport industry. Examination of customer relationship management methods and sales techniques in sport.', ARRAY[]::TEXT[], NULL),
    ('SPH-M 615', 'FINANCIAL ANALYSIS IN SPORT', '36836', 'Class Status', NULL, NULL, 'Jiayao Qi', 4, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
