    ('SPH-N 301', 'METHODS OF NUTRITIONAL ASSESSMENT', '10789', 'Class Status', 'Tu Tuesday 9:10 AM–10:00 AM', 'LH 135', 'Nana Gletsu Miller', 6, 'Lecture', 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'A theoretical and practical review of methods used to assess nutritional status of individuals and populations.', ARRAY[]::TEXT[], NULL),
    ('SPH-N 301', 'METHODS OF NUTRITIONAL ASSESSMENT', '10790', 'Class Status', 'Th Thursday 9:05 AM–11:05 AM', 'PH 09', 'Nana Gletsu Miller, Lisa Spence', 6, 'Laboratory', 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'A theoretical and practical review of methods used to assess nutritional status of individuals and populations.', ARRAY[]::TEXT[], NULL),
    ('SPH-N 305', 'APPLIED SPORTS NUTRITION', '9381', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WY 115', 'Melissa Greives', 11, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'Review of macro and micronutrients, and energy metabolism in the context of sport; focus on nutrient requirements for active individuals and athletes with an emphasis on sport-specific nutritional needs; nutrition strategies for optimizing sports performance, enhancing health, minimizing injury; current topics in sports nutrition.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-N 321', 'QUANTITY FOOD PURCHASING/PROD', '1998', 'Class Status', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'SY 103 SY 103', 'Victoria Getty', 14, NULL, 'Lecture', '4', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Principles of menu planning and pricing, equipment selection, food product flow, and cost control in foodservice operations. Class includes service-learning, tours of community foodservice related facilities, and experience in the university dining halls.', ARRAY[]::TEXT[], NULL),
    ('SPH-N 336', 'PUBLIC HEALTH NUTRITION', '1999', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'WY 115', 'Krisha Thiagarajah', 12, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'Via lecture, discussions, and practical applications, the course will introduce students to the field of public health nutrition, including community assessment; program development, implementation, and evaluation; budget development; eligibility and services available through existing programs; cultural foodways; and the intersection of public policy and nutrition.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-N 336', 'PUBLIC HEALTH NUTRITION', '7703', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'SY 103', 'Krisha Thiagarajah', 14, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'Via lecture, discussions, and practical applications, the course will introduce students to the field of public health nutrition, including community assessment; program development, implementation, and evaluation; budget development; eligibility and services available through existing programs; cultural foodways; and the intersection of public policy and nutrition.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-N 401', 'ISSUES IN DIETETICS', '3103', 'Class Status', 'M Monday 1:55 PM–2:45 PM', 'SY 103', 'Victoria Getty', 9, NULL, 'Lecture', '1', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'A culminating class to address current issues in dietetics, including such topics as medical ethics, CAM, and reimbursement for services. Students will develop a career portfolio and ready themselves for the dietetic internship process.', ARRAY[]::TEXT[], NULL),
    ('SPH-N 430', 'ADVANCED NUTRITION I', '3350', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'WH 121', 'Sixtus Aguree, Krisha Thiagarajah', 14, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Functions of nutrients in human metabolism; evaluation and fulfillment of nutritional needs; current literature. Emphasis on the energy nutrients: protein, carbohydrates, and fats.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-N 431', 'MEDICAL NUTRITION THERAPY', '7877', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'WH 005', 'Melissa Greives', 16, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-N 492', 'RSRCH IN NUTRITION/DIETETICS', '11018', 'Closed', NULL, NULL, 'Staff', 0, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Undergraduate research in the field of nutrition/dietetics under the direction of a faculty member in the department.', ARRAY[]::TEXT[], NULL),
    ('SPH-N 530', 'ADVANCED HUMAN NUTRITION', '2000', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'WH 121', 'Sixtus Aguree, Krisha Thiagarajah', 11, 'Lecture', 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Function of carbohydrates, protein and fat in human metabolism, energy balance, and review of current literature.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-N 530', 'ADVANCED HUMAN NUTRITION', '37352', 'Class Status', 'M Monday 11:00 AM–12:00 PM', 'AC C101', 'Sixtus Aguree, Krisha Thiagarajah', 13, 'Discussion', 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Function of carbohydrates, protein and fat in human metabolism, energy balance, and review of current literature.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-N 531', 'MEDICAL NUTRITION THERAPY', '8200', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'WH 005', 'Melissa Greives', 4, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Emphasis on the physiology, etiology, and dietary intervention in various diseased states. Includes in-depth analysis and reporting of a disease state and the role of diet and clinical research in its management.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-N 536', 'APPLIED PUBLIC HEALTH NUTRITION', '4719', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'WY 115', 'Krisha Thiagarajah', 10, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'Course includes community assessment; program development, implementation, and evaluation; budget development; eligibility and services available through existing programs; cultural foodways; and the intersection of public policy and nutrition.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-N 691', 'READINGS IN NUTRITION SCIENCE', '3133', 'Class Status', NULL, NULL, 'Cydne Perry', 9, NULL, 'Readings', '1–5', NULL, ARRAY[]::TEXT[], 'Planned readings in specialized areas of professional interest are conducted under the direction of a member of the graduate faculty. Enrollment is limited to advanced graduate students.', ARRAY[]::TEXT[], NULL),
    ('SPH-N 691', 'READINGS IN NUTRITION SCIENCE', '13135', 'Class Status', NULL, NULL, 'Sixtus Aguree', 9, NULL, 'Readings', '1–5', NULL, ARRAY[]::TEXT[], 'Planned readings in specialized areas of professional interest are conducted under the direction of a member of the graduate faculty. Enrollment is limited to advanced graduate students.', ARRAY[]::TEXT[], NULL),
    ('SPH-N 694', 'GRADUATE SEMINAR IN NUTRITION', '12942', 'Class Status', 'W Wednesday 2:20 PM–3:20 PM', 'AC C107', 'Temitope Erinosho', 5, NULL, 'Seminar', '1', 'CEDAR HALL', ARRAY[]::TEXT[], 'This seminar course will include presentation and discussion of research in the field of nutritional sciences. Research methods, analysis, and interpretation of findings will be a focus.', ARRAY[]::TEXT[], NULL),
    ('SPH-N 700', 'NUTRITION RESEARCH METHODS, RIGOR, REPRODUCIBILITY, AND TRANSPARENCY', '13061', 'Class Status', 'M Monday 3:55 PM–5:10 PM', 'BH 315', 'Cydne Perry', 7, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Research methods used in the nutritional sciences will be a focus. Foundation topics in methodology will include hypothesis formation and testing, study design, sampling, randomization, comparator conditions, treatment fidelity, and process evaluation. Steps to ensure scientific rigor, reproducibility, and transparency when implementing studies also will be addressed.', ARRAY[]::TEXT[], NULL),
    ('SPH-N 730', 'REGULATION OF NUTRIENT METABOLISM I', '14507', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'SY 200', 'Cydne Perry', 7, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'The objective of the course is to build on students'' existing core nutrition knowledge and to enhance in-depth knowledge of the structure, biochemical, and metabolic functions of the macronutrients.', ARRAY[]::TEXT[], NULL),
    ('SPH-O 214', 'WILDFLOWERS & WILD EDIBLES', '2004', 'Class Status', 'Tu Tuesday 3:55 PM–5:55 PM', 'LH 135', 'Julia Erwin', 2, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Students will gain a knowledge for identification of wildflowers and wild edible plants. Activities may include a weekend field trip, a chance to improve skills in identifying local plants, as well as a culinary experience in wild edibles.', ARRAY[]::TEXT[], NULL),
    ('SPH-O 214', 'WILDFLOWERS & WILD EDIBLES', '32621', 'Class Status', 'Th Thursday 3:55 PM–5:55 PM', 'WH 005', 'Julia Erwin', 8, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Students will gain a knowledge for identification of wildflowers and wild edible plants. Activities may include a weekend field trip, a chance to improve skills in identifying local plants, as well as a culinary experience in wild edibles.', ARRAY[]::TEXT[], NULL),
    ('SPH-O 244', 'NATURAL HISTORY AND FIELD ECOLOGY', '13160', 'Closed', 'W Wednesday 12:45 PM–5:25 PM', 'HD TBA', 'Jeremy Armstrong', 0, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This course will review general concepts related to ecology and natural history. The course is based on individual exploration and investigations. Concepts pertaining to ecology and natural history will be presented through lecture / discussion and reinforced through fieldwork. In other words, you will get dirty.', ARRAY[]::TEXT[], NULL),
    ('SPH-O 279', 'OUTDOOR ADVENTURE EDUCATION', '10119', 'Class Status', 'M Monday 1:55 PM–4:25 PM', 'HD TBA', 'Daniela Berry', 18, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Overview focusing on theoretical concepts and common practices. Investigation and elucidation of theory and philosophy via a mixture of abstracted knowledge and practical involvement in a backcountry environment.', ARRAY[]::TEXT[], NULL),
    ('SPH-O 305', 'INTEGRATED RESOURCE MANAGEMENT', '9074', 'Class Status', 'F Friday 8:00 AM–10:30 AM', 'WH 109', 'Brian Forist', 14, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Provides a managerial understanding of ecological concepts, resource management practices, and resource policies related to natural resource/land management. Focus on allocation of resources, carrying capacity, resource protection, and environmental impacts of uses on natural resources.', ARRAY[]::TEXT[], NULL),
    ('SPH-O 310', 'ECOSYSTEM MANAGEMENT', '2006', 'Class Status', 'Th Thursday 2:00 PM–4:45 PM', 'AC C116', 'Joel Pontius', 1, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Study of basic concepts, theories, and importance for outdoor recreation, with particular emphasis on key aspects of ecosystems that are conducive to successful and sustainable environmental communities, impacts of strategies on resource sites, and best practices. Required field work.', ARRAY[]::TEXT[], NULL),
    ('SPH-P 309', 'PUBLIC HEALTH ADMINISTRATION', '10652', 'Class Status', 'MW Monday, Wednesday 8:00 AM–9:20 AM', 'GY 1045', 'Priscilla Barnes, Jon Macy', 12, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Students are expected to learn principles of population-based management in order to administer programs, services, and policies within the U.S. public health system. In addition, students examine the mission, structure, and processes of local, state, and federal organizations in delivering population-based programs, services and policies.', ARRAY[]::TEXT[], NULL),
    ('SPH-P 561', 'FINANCE & BUDGETING IN PUBLIC HEALTH', '6223', 'Class Status', NULL, 'WB WEB', 'Jeanie Alter', 16, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Trends in finance, budgetary procedures, management of funds, cost analysis, purchasing and property control, leases and contractual agreements and other management concerns.', ARRAY[]::TEXT[], NULL),
    ('SPH-P 680', 'PUBLIC HEALTH ECONOMICS', '6970', 'Class Status', 'Thirteen Week', 'WB WEB', 'William McConnell', 20, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Economics is a discipline to explain human beings'' behaviors and also serves as an important point of view for analyzing public health issues and associated policies. This course will guide students to think through a number of public health issues using economics tools.', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 381', 'INTRODUCTION TO BIOSTATISTICS', '11462', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WH 111', 'David Fluharty', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'A conceptual approach is utilized to introduce students to sources of public health data. Basic concepts and models are available to understand and analyze data and information related to prevention of diseases and promotion of health and determinants of health behavior.', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 381', 'INTRODUCTION TO BIOSTATISTICS', '11594', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WH 111', 'David Fluharty', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'A conceptual approach is utilized to introduce students to sources of public health data. Basic concepts and models are available to understand and analyze data and information related to prevention of diseases and promotion of health and determinants of health behavior.', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 381', 'INTRODUCTION TO BIOSTATISTICS', '34082', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'SB 150', 'Wenxue Lin', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'A conceptual approach is utilized to introduce students to sources of public health data. Basic concepts and models are available to understand and analyze data and information related to prevention of diseases and promotion of health and determinants of health behavior.', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 381', 'INTRODUCTION TO BIOSTATISTICS', '3104', 'Closed', NULL, 'WB WEB', 'Mikyoung Jun', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'A conceptual approach is utilized to introduce students to sources of public health data. Basic concepts and models are available to understand and analyze data and information related to prevention of diseases and promotion of health and determinants of health behavior.', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 400', 'INTRODUCTION TO BIOSTATISTICAL COMPUTING', '9333', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'SY 006', 'Wenxue Lin', 10, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'This course is designed to familiarize students with statistical computing and data management with emphasis on the R programming language. The course includes a lecture and practical component. Topics include: Producing descriptive statistics, graphs, and reports; Reading, writing, combining, and transforming data sets; Create functions in R.', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 501', 'INTRO TO STATS IN PUBLIC HLTH', '13341', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 344', 'David Fluharty', 20, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'An applied approach to the collection, organization, analyses and interpretation of data pertinent to public health and vital statistics is outlined. The application of statistical and biostatistical methods to public health is explained.', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 501', 'INTRO TO STATS IN PUBLIC HLTH', '10126', 'Class Status', NULL, 'WB WEB', 'David Fluharty', 54, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'An applied approach to the collection, organization, analyses and interpretation of data pertinent to public health and vital statistics is outlined. The application of statistical and biostatistical methods to public health is explained.', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 605', 'ANALYSIS OF MULTI-LEVEL AND LONGITUDINAL DATA', '11863', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 217', 'Carmen Tekwe', 8, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course introduces modern statistical methods for longitudinal data analysis to graduate students who need to understand research reports/scientific papers, analyze empirical data, or interpret their results. The topics covered by this course include SAS tutorial, review of linear regression, linear mixed models, generalized linear mixed models, and generalized estimating equations (GEE).', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 611', 'STATISTICAL PACKAGES IN RESEARCH', '13296', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'WH 009', 'Marco Ajelli', 8, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course serves as an introduction to SAS for data management, data analysis, and statistical reporting. Emphasis is placed on data management. The course will include lectures, computer lab practices, and a final project.', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 611', 'STATISTICAL PACKAGES IN RESEARCH', '11721', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'WB WEB', 'Indrakshi Roy', 60, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course serves as an introduction to SAS for data management, data analysis, and statistical reporting. Emphasis is placed on data management. The course will include lectures, computer lab practices, and a final project.', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 612', 'SURVIVAL ANALYSIS', '11875', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'SY 103', 'Ethan Fridmanski', 16, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Covers basic concepts of survival analysis, such as Kaplan-Meier estimates, hazard functions, survival functions, logrank tests. Parametric and nonparametric inferences for survival data.', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 631', 'QUANTITATIVE METHODS I FOR APPLIED PUBLIC HEALTH RESEARCH', '36211', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:55 AM', 'WB WEB', 'Dong Chul Seo', 17, 'Lecture', 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course covers fundamental and intermediate statistical techniques, data analytical approaches that are commonly used in applied public health research, and R programming language. It was designed to prepare graduate students studying behavioral health, population health, and applied public health to take advanced statistics courses.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-Q 631', 'QUANTITATIVE METHODS I FOR APPLIED PUBLIC HEALTH RESEARCH', '36212', 'Class Status', 'F Friday 9:20 AM–10:50 AM', 'WB WEB', 'Dong Chul Seo', 17, 'Laboratory', 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course covers fundamental and intermediate statistical techniques, data analytical approaches that are commonly used in applied public health research, and R programming language. It was designed to prepare graduate students studying behavioral health, population health, and applied public health to take advanced statistics courses.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-Q 651', 'INTRODUCTION TO STATISTICAL DISTRIBUTIONS IN PUBLIC HEALTH', '12183', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'SY 004', 'Roger Zoh', 6, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Introduction to probability and statistical models, using the R software applied to public health datasets. Conditional probability and independence, discrete and continuous random variables, and mass, density, and moment generating functions. Joint, marginal, and conditional distributions, and behavior under changes of variables. Neither multivariable calculus nor linear algebra is assumed.', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 699', 'THESIS RESEARCH IN BIOSTATISTICS', '34807', 'Class Status', NULL, NULL, 'Roger Zoh', 9, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'This course provides an environment for mentored research designed to answer the research questions from M.S students in Biostatistics. The credit hours may be taken over several semesters so the content of the work will progress from initial study design to implementation, analysis and manuscript preparation.', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 703', 'GENERALIZED LINEAR MODELS', '11199', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 333', 'Javier Rojo', 5, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course covers all aspects of generalized linear models. Some of the topics to be discussed include conditional likelihoods, generalized estimating equations, and quasi-likelihoods. Both continuous and discrete outcomes will be considered. The SAS and/or R software will be used extensively.', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 711', 'ADVANCED BIOSTATISTICAL COMPUTING', '15158', 'Class Status', 'TuTh Tuesday, Thursday 4:00 PM–5:15 PM', 'HD TBA', 'Raul Cruz', 7, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'As an introduction to statistical computing using the R programming language, this course is designed to develop students'' abilities to perform advanced statistical computing skills. The presentation of this course will focus on implementation and application rather than theory.', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 794', 'DOCTORAL SEMINAR IN BIOSTATISTICS', '11861', 'Class Status', 'F Friday 12:45 PM–2:45 PM', 'WH 111', 'Carmen Tekwe', 50, NULL, 'Lecture', '1', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course will equip students with skills to apply biostatistics concepts to critically evaluate research reports in the public health and medical literature.', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 799', 'DISSERTATION RESEARCH IN BIOSTATISTICS', '12058', 'Class Status', NULL, NULL, 'Roger Zoh', 13, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'This course provides an environment for mentored research designed to answer the doctoral candidate''s research question. The credit hours are meant to be taken over several semesters so the content of the work will progress from initial study design to implementation, analysis and manuscript preparation.', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 799', 'DISSERTATION RESEARCH IN BIOSTATISTICS', '12059', 'Class Status', NULL, NULL, 'Nianjun Liu', 14, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'This course provides an environment for mentored research designed to answer the doctoral candidate''s research question. The credit hours are meant to be taken over several semesters so the content of the work will progress from initial study design to implementation, analysis and manuscript preparation.', ARRAY[]::TEXT[], NULL),
    ('SPH-Q 799', 'DISSERTATION RESEARCH IN BIOSTATISTICS', '12060', 'Class Status', NULL, NULL, 'Jaroslaw Harezlak', 14, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'This course provides an environment for mentored research designed to answer the doctoral candidate''s research question. The credit hours are meant to be taken over several semesters so the content of the work will progress from initial study design to implementation, analysis and manuscript preparation.', ARRAY[]::TEXT[], NULL),
