    ('SPH-Q 799', 'DISSERTATION RESEARCH IN BIOSTATISTICS', '12118', 'Class Status', NULL, NULL, 'Carmen Tekwe', 13, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'This course provides an environment for mentored research designed to answer the doctoral candidate''s research question. The credit hours are meant to be taken over several semesters so the content of the work will progress from initial study design to implementation, analysis and manuscript preparation.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 142', 'LIVING WELL', '8108', 'Class Status', 'MW Monday, Wednesday 7:05 PM–8:20 PM', 'RA B111', 'Myc Wiatrowski', 11, NULL, 'Lecture', '3', 'SPRUCE HALL', ARRAY[]::TEXT[], 'Broaden your view of living well by actively pursuing healthy lifestyles. This course utilizes HPER faculty and professionals throughout the Bloomington community to help students achieve balance in health, physical activity, and leisure pursuits. Students address concepts of peer mentoring and goal setting strategies to achieve this balance.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPH-R 142', 'LIVING WELL', '8745', 'Class Status', NULL, 'WB WEB', 'Edlin Garcia', 1, NULL, 'Lecture', '3', 'SPRUCE HALL', ARRAY[]::TEXT[], 'Broaden your view of living well by actively pursuing healthy lifestyles. This course utilizes HPER faculty and professionals throughout the Bloomington community to help students achieve balance in health, physical activity, and leisure pursuits. Students address concepts of peer mentoring and goal setting strategies to achieve this balance.', ARRAY['IUB GenEd S&H credit'], NULL),
