    ('SPH-R 142', 'LIVING WELL', '13360', 'Closed', NULL, 'WB WEB', 'Blair McKissock', 0, NULL, 'Lecture', '3', 'SPRUCE HALL', ARRAY[]::TEXT[], 'Broaden your view of living well by actively pursuing healthy lifestyles. This course utilizes HPER faculty and professionals throughout the Bloomington community to help students achieve balance in health, physical activity, and leisure pursuits. Students address concepts of peer mentoring and goal setting strategies to achieve this balance.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPH-R 200', 'HEALTH AND HAPPINESS BY DESIGN', '5849', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'MO 007', 'Brian Forist', 16, NULL, 'Lecture', '3', 'MORRISON HALL', ARRAY[]::TEXT[], 'Introduction to leisure as a significant force in contemporary life, a human behavior spanning history and cultures, and an essential contributor to public health. Focus on the relation of leisure to the public health of individuals and communities by studying its social, psychological, historical, philosophical, economic, anthropological, and geographical foundations.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPH-R 200', 'HEALTH AND HAPPINESS BY DESIGN', '5850', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'MO 007', 'Brian Forist', 47, NULL, 'Lecture', '3', 'MORRISON HALL', ARRAY[]::TEXT[], 'Introduction to leisure as a significant force in contemporary life, a human behavior spanning history and cultures, and an essential contributor to public health. Focus on the relation of leisure to the public health of individuals and communities by studying its social, psychological, historical, philosophical, economic, anthropological, and geographical foundations.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPH-R 200', 'HEALTH AND HAPPINESS BY DESIGN', '35827', 'Class Status', NULL, 'WB WEB', 'Becca Lassell', 91, NULL, 'Lecture', '3', 'MORRISON HALL', ARRAY[]::TEXT[], 'Introduction to leisure as a significant force in contemporary life, a human behavior spanning history and cultures, and an essential contributor to public health. Focus on the relation of leisure to the public health of individuals and communities by studying its social, psychological, historical, philosophical, economic, anthropological, and geographical foundations.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPH-R 200', 'HEALTH AND HAPPINESS BY DESIGN', '5848', 'Closed', NULL, 'WB WEB', 'Brian Forist', 0, NULL, 'Lecture', '3', 'MORRISON HALL', ARRAY[]::TEXT[], 'Introduction to leisure as a significant force in contemporary life, a human behavior spanning history and cultures, and an essential contributor to public health. Focus on the relation of leisure to the public health of individuals and communities by studying its social, psychological, historical, philosophical, economic, anthropological, and geographical foundations.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPH-R 210', 'INCLUSION IN HEALTH & WELLNESS DESIGN', '2005', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'WH 101', 'Blair McKissock', 115, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Overview and rationale for the provision of recreation, park, and tourism services for all populations and ages with a focus on individuals with disabilities. Moral and legal issues, relevant terminology, accessibility guidelines, awareness of needs and abilities of under-represented groups, and techniques for the inclusion of individuals of all abilities.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 210', 'INCLUSION IN HEALTH & WELLNESS DESIGN', '11101', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'WH 101', 'Blair McKissock', 7, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Overview and rationale for the provision of recreation, park, and tourism services for all populations and ages with a focus on individuals with disabilities. Moral and legal issues, relevant terminology, accessibility guidelines, awareness of needs and abilities of under-represented groups, and techniques for the inclusion of individuals of all abilities.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 220', 'FOUNDATIONS OF PARKS, RECREATION & THE OUTDOORS', '8815', 'Closed', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'LH 102', 'Julia Knapp', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Exploration of the uniqueness of public and nonprofit recreation service providers, including their history and mission, while developing an understanding of community and societal issues related to their programs, services and administration of these agencies, and the nature of working in public service.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 221', 'CREATING SENSE OF PLACE THROUGH DESIGN', '11102', 'Class Status', 'M Monday 1:55 PM–4:25 PM', 'HD TBA', 'Brian Forist', 5, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-R 230', 'RECREATIONAL SPORTS PROGRAMMING', '8926', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WY 015', 'Ryan Fitzgerald', 0, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-R 235', 'SPORT AND VIOLENCE', '7697', 'Class Status', NULL, 'WB WEB', 'Misty Hawkins', 36, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course explores the roots of violence from the context of sport. Foundations are examined in the theoretical framework of sport in society from historical, sociological, psychological, and anthropological perspectives, as well as linkage to contemporary resources that address this problem.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 235', 'SPORT AND VIOLENCE', '13435', 'Class Status', NULL, 'WB WEB', 'Julia Knapp', 50, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course explores the roots of violence from the context of sport. Foundations are examined in the theoretical framework of sport in society from historical, sociological, psychological, and anthropological perspectives, as well as linkage to contemporary resources that address this problem.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 311', 'MANAGEMENT IN HEALTH & WELLNESS DESIGN', '5937', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'SE 140', 'Julia Knapp', 1, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'The focus of the course is the study of management principles and practices of the public agency, non-profit association, and private for-profit enterprise operating parks, recreation areas and facilities, and providing recreation programs/ services. No matter where students pursue a career, they all will need management/leadership skills to be successful.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 311', 'MANAGEMENT IN HEALTH & WELLNESS DESIGN', '12119', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'SE 140', 'Julia Knapp', 7, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'The focus of the course is the study of management principles and practices of the public agency, non-profit association, and private for-profit enterprise operating parks, recreation areas and facilities, and providing recreation programs/ services. No matter where students pursue a career, they all will need management/leadership skills to be successful.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 312', 'CAREER PERSPECTIVES & INTERNSHIP PREPARATION', '5619', 'Class Status', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'WH 003', 'Julia Knapp', 28, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Survey of recreation, park, and tourism services as a career field, to familiarize students with concepts related to professionalism and the internship and job search process. Students will practice the process of career planning through self-assessment and exploration of career options, and will receive feedback on interview and writing skills.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 314', 'DATA-BASED DECISION-MAKING METHODS', '5945', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'AC C002', 'Edmond Ramly', 3, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Overview of the processes of research and evaluation as encountered in leisure services. Development of inquiry skills useful for planning and management, and various methods of effective information collection and synthesis. Practice using factual evidence to support programming or planning decisions and to document the outcomes of programs being implemented.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 314', 'DATA-BASED DECISION-MAKING METHODS', '11111', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'AC C002', 'Edmond Ramly', 5, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Overview of the processes of research and evaluation as encountered in leisure services. Development of inquiry skills useful for planning and management, and various methods of effective information collection and synthesis. Practice using factual evidence to support programming or planning decisions and to document the outcomes of programs being implemented.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 321', 'AQUATIC MANAGEMENT', '11365', 'Class Status', NULL, 'WB WEB', 'Kellen Edelbrock', 28, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-R 388', 'EXPERIENCE MARKETING', '5938', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'WH 004', 'Haoai Zhao', 19, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Application of marketing principles to leisure service delivery systems, including procedures for developing marketing plans for leisure service organizations and agencies. Emphasis on organizing and analyzing the marketing process and planning the marketing mix, including product, price, place, and promotion.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 391', 'READINGS IN RPTS', '6055', 'Class Status', NULL, NULL, 'William Ramos', 5, NULL, 'Lecture', '1–3', NULL, ARRAY[]::TEXT[], 'Individualized advanced study of specific topics under faculty direction.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 391', 'READINGS IN RPTS', '11651', 'Class Status', NULL, NULL, 'Brian Forist', 2, NULL, 'Lecture', '1–3', NULL, ARRAY[]::TEXT[], 'Individualized advanced study of specific topics under faculty direction.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 396', 'WORK EXPERIENCE IN RPTS', '6298', 'Class Status', NULL, NULL, 'William Ramos', 5, NULL, 'Field Trip', '0', NULL, ARRAY[]::TEXT[], 'This class allows students on a visa to register when completing curricular practical training or other work experience, such as the 320 Hours, required for a Recreation degree.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 410', 'EVENT PLANNING AND PROGRAM DEVELOPMENT', '5517', 'Class Status', 'MWF Monday, Wednesday, Friday 8:00 AM–8:50 AM', 'BH 203', 'Becky Higgins', 12, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Students learn event planning and program techniques while applying course materials to real-world experiences through service learning. Students will develop and facilitate event planning and recreation programs through the study of a variety of models including the event/program development cycle.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-R 414', 'LEGAL ASPECTS IN HEALTH AND WELLNESS DESIGN', '11113', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'WH 004', 'Drew Pickett', 5, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'The course is designed to educate leisure service managers about the legal risks & considerations inherent in the management of programs to avoid/reduce the probability of litigation. The course provides students with a basic understanding of legal procedures, intellectual property law, & other legal subjects related to leisure services.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 414', 'LEGAL ASPECTS IN HEALTH AND WELLNESS DESIGN', '7098', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'WH 004', 'Drew Pickett', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'The course is designed to educate leisure service managers about the legal risks & considerations inherent in the management of programs to avoid/reduce the probability of litigation. The course provides students with a basic understanding of legal procedures, intellectual property law, & other legal subjects related to leisure services.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 426', 'HUMAN RESOURCE MANAGEMENT IN HEALTH AND WELLNESS DESIGN', '2008', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WY 015', 'Mark Miller', 31, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'Principles and practices of human resource management in recreation and leisure service agencies, emphasizing the skills necessary to manage full-time, part-time, and seasonal employees and volunteers. The class will consist of lectures, discussion, case studies, team/group discussions, video presentations, and exercises. Opportunities for supervisory skill development will be provided.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-R 497', 'PROFESSIONAL INTERNSHIP', '5939', 'Class Status', NULL, NULL, 'Jared Allsop', 14, NULL, 'Internship', '12', NULL, ARRAY[]::TEXT[], 'Supervised real world experience for students to practice the relevant knowledge and skills required to enter careers in recreation and leisure, and to extend their professional network. Interns will have a site supervisor and an Indiana University Internship Coordinator who assigns specific tasks and evaluates the intern''s work.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 497', 'PROFESSIONAL INTERNSHIP', '5940', 'Class Status', NULL, NULL, 'Julia Knapp', 60, NULL, 'Internship', '12', NULL, ARRAY[]::TEXT[], 'Supervised real world experience for students to practice the relevant knowledge and skills required to enter careers in recreation and leisure, and to extend their professional network. Interns will have a site supervisor and an Indiana University Internship Coordinator who assigns specific tasks and evaluates the intern''s work.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 510', 'PHIL OF LEISURE & RECREATION', '2011', 'Closed', NULL, 'WB WEB', 'Daniela Berry', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Exploration of philosophical, ethical, historical, and cultural foundations for recreation in society; challenge of leisure and role of recreation in present and future environments.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 512', 'ADMN THEORY/MGT PRC OF LEISURE', '9343', 'Class Status', NULL, 'WB WEB', 'Sarah Young', 12, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Investigations of how administrative theory and management practices in leisure services have changed since 1900. Involves the study of contemporary and future management issues influencing the delivery of leisure services in public and nonprofit settings. Particular emphasis given to implications for leisure service managers and organizational responses.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 542', 'FISCAL MANAGEMENT IN RECREATION ADMINISTRATION', '29869', 'Class Status', NULL, 'WB WEB', 'Ronald Orner', 14, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Students will develop an understanding of key fundamental fiscal management concepts and skills relevant to the field of Recreation.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 598', 'MASTER''S PROJECT IN ADMIN', '3642', 'Class Status', NULL, NULL, 'Shu Cole', 4, NULL, 'Independent Study', '2–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-R 598', 'MASTER''S PROJECT IN ADMIN', '9138', 'Class Status', NULL, NULL, 'Brian Forist', 4, NULL, 'Independent Study', '2–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-R 691', 'READINGS IN RECREATION', '8465', 'Class Status', NULL, 'WB WEB', 'Jeanne Johnston', 30, NULL, 'Lecture', '1–5', 'WEB-BASED CLASS', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-R 693', 'INDEPENDENT STUDY & RESEARCH', '9146', 'Class Status', NULL, NULL, 'Brian Forist', 4, NULL, 'Independent Study', '1–5', NULL, ARRAY[]::TEXT[], 'Independent research conducted under guidance of a graduate faculty member.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 693', 'INDEPENDENT STUDY & RESEARCH', '34947', 'Class Status', NULL, NULL, 'Armando Peña', 4, NULL, 'Independent Study', '1–5', NULL, ARRAY[]::TEXT[], 'Independent research conducted under guidance of a graduate faculty member.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 695', 'PRACT IN RECREATION & PARKS', '9151', 'Class Status', NULL, NULL, 'Brian Forist', 5, NULL, 'Practicum', '1–6', NULL, ARRAY[]::TEXT[], 'Field experience as specified in written individualized contracts with supervising faculty. Practicums are available in the following areas of emphasis: park/recreation administration, recreational sports administration, therapeutic recreation, outdoor recreation, tourism, armed forces recreation, and resource management.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 695', 'PRACT IN RECREATION & PARKS', '9152', 'Class Status', NULL, NULL, 'Julia Knapp', 5, NULL, 'Practicum', '1–6', NULL, ARRAY[]::TEXT[], 'Field experience as specified in written individualized contracts with supervising faculty. Practicums are available in the following areas of emphasis: park/recreation administration, recreational sports administration, therapeutic recreation, outdoor recreation, tourism, armed forces recreation, and resource management.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 695', 'PRACT IN RECREATION & PARKS', '9153', 'Class Status', NULL, NULL, 'Jared Allsop', 5, NULL, 'Practicum', '1–6', NULL, ARRAY[]::TEXT[], 'Field experience as specified in written individualized contracts with supervising faculty. Practicums are available in the following areas of emphasis: park/recreation administration, recreational sports administration, therapeutic recreation, outdoor recreation, tourism, armed forces recreation, and resource management.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 696', 'MPH FIELD EXPERIENCE IN PARKS AND RECREATION', '11009', 'Class Status', NULL, 'HD TBA', 'Brian Forist', 1, NULL, 'Practicum', '4', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Public health skills are developed through professional experiences in public health settings facilitated by preceptors and supervised by faculty. Regular critiques are held with supervisors, written progress reports and development of a major independent project are required.', ARRAY[]::TEXT[], NULL),
    ('SPH-R 697', 'INTERNSHIPS IN RECREATN&PARKS', '6863', 'Class Status', NULL, NULL, 'Jared Allsop', 4, NULL, 'Independent Study', '2–8', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-R 697', 'INTERNSHIPS IN RECREATN&PARKS', '9154', 'Class Status', NULL, NULL, 'Brian Forist', 5, NULL, 'Independent Study', '2–8', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-R 697', 'INTERNSHIPS IN RECREATN&PARKS', '9155', 'Class Status', NULL, NULL, 'Julia Knapp', 5, NULL, 'Independent Study', '2–8', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-R 799', 'PH.D.DISSERTATION', '4826', 'Class Status', NULL, NULL, 'Joseph Chen', 10, NULL, 'Independent Study', '1–30', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-R 799', 'PH.D.DISSERTATION', '4827', 'Class Status', NULL, NULL, 'Shu Cole', 7, NULL, 'Independent Study', '1–30', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-R 799', 'PH.D.DISSERTATION', '6004', 'Class Status', NULL, NULL, 'William Ramos', 10, NULL, 'Independent Study', '1–30', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-R 799', 'PH.D.DISSERTATION', '8721', 'Class Status', NULL, NULL, 'William Ramos', 10, NULL, 'Independent Study', '1–30', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-R 799', 'PH.D.DISSERTATION', '9252', 'Class Status', NULL, NULL, 'Evan Jordan', 10, NULL, 'Independent Study', '1–30', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-S 101', 'INTRODUCTION TO SAFETY', '33153', 'Closed', NULL, 'OL ONLINE', 'Abdulrazak Balogun', 0, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'Provides an overview of the variety of careers available in the safety profession. Examines the broad areas practiced by safety professionals including regulatory compliance, environmental protection, ergonomics, industrial hygiene, emergency management, recreational safety, personal safety, healthcare, training and instruction, system safety, fire protection, and hazaroud materials management.', ARRAY[]::TEXT[], NULL),
    ('SPH-S 201', 'INTRO TO INDUSTRIAL HYGIENE', '33154', 'Class Status', NULL, 'OL ONLINE', 'Abdulrazak Balogun', 4, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'The concepts, principles, and techniques in the practice of industrial hygiene are presented. The identification, evaluation, and control of occupational health hazards are discussed. An orientation to selected instrumentation used to assess the workplace is provided.', ARRAY[]::TEXT[], NULL),
    ('SPH-S 214', 'OSHA CONSTRUCTION STANDARDS', '33155', 'Class Status', NULL, 'OL ONLINE', 'Earl Blair', 5, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'An introduction to and application of the Occupational Safety and Health Administration (OSHA) and Indiana OSHA (IOSHA) construction standards as they apply to both the private and public sectors. Course includes an inspection practicum.', ARRAY[]::TEXT[], NULL),
    ('SPH-S 345', 'SAFETY PROGRAM MANAGEMENT', '33156', 'Class Status', NULL, 'OL ONLINE', 'Todd Smith', 6, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-S 410', 'ADVANCED INDUSTRIAL HYGIENE', '33157', 'Class Status', NULL, 'OL ONLINE', 'Kevin Slates', 12, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'Provides definitive application of principles and concepts for the solutions of workplace health and physical hazards. Program management techniques are discussed. Research procedures and techniques are introduced through individual and group projects.', ARRAY[]::TEXT[], NULL),
    ('SPH-S 415', 'SAFETY EDUCATION & TRAINING', '33158', 'Class Status', NULL, 'OL ONLINE', 'Abdulrazak Balogun', 6, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'Assessing training and education needs, establishing goals and objectives, planning and methods for delivery, using resources and evaluating effectiveness. Students develop evaluation instruments and conduct mock OSHA training. Emphasis is on improving safety performance in addition to compliance.', ARRAY[]::TEXT[], NULL),
    ('SPH-S 496', 'FIELD EXPER OCCUP SAFETY', '5716', 'Class Status', NULL, NULL, 'Kevin Slates', 9, NULL, 'Independent Study', '1–10', NULL, ARRAY[]::TEXT[], 'Field experience through on-the-job and related opportunities in occupational safety. Students will be assigned to industrial and occupational enterprises offering professional development for the safety specialist. Periodic critiques will be scheduled with supervisory personnel. Written progress reports will be required.', ARRAY[]::TEXT[], NULL),
    ('SPH-S 502', 'INSTRUCT STRAT FOR SAFETY EDUC', '3623', 'Class Status', NULL, 'WB WEB', 'Kevin Slates', 9, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-S 590', 'INTRODUCTION TO RESEARCH IN SAFETY MANAGEMENT', '7704', 'Class Status', NULL, 'WB WEB', 'Todd Smith', 7, NULL, 'Methods Course', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Provides in depth coverage of research methods and techniques commonly applied in the areas of safety science, safety management, occupational safety, occupational health and injury and illness prevention. Emphasis on developing the capacity to critically interpret, evaluate and apply findings from the research literature in appropriate contexts.', ARRAY[]::TEXT[], NULL),
    ('SPH-S 610', 'OCCUPATIONAL RISK MANAGEMENT', '4290', 'Class Status', NULL, 'WB WEB', 'Kevin Slates', 7, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Evaluation and assessment of various workplace regulations. Seminars and directed reading focus on risk strategies utilized in recognizing, evaluating and controlling occupational and environmental hazards associated with public and private sectors.', ARRAY[]::TEXT[], NULL),
    ('SPH-S 650', 'SEMINAR IN SAFETY EDUCATION', '8463', 'Class Status', NULL, 'WB WEB', 'Dong Chul Seo', 5, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Contemporary topics in the area of safety education are studied under the direction of faculty members with specialized areas of expertise. Specific topics vary.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPH-T 201', 'INTRODUCTION TO TOURISM, HOSPITALITY, AND EVENT MANAGEMENT INDUSTRIES', '2003', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'WH 120', 'Shu Cole', 40, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPH-T 203', 'PRINCIPLES OF LODGING MANAGEMENT', '7177', 'Closed', 'M Monday 5:30 PM–8:00 PM', 'GA 1118', 'Joseph Chen', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course provides an overview of lodging management from the perspectives of history, operations, and future trends. The course intends to assist students to acquire rich insights on the operation of the lodging business that entails the domains of: (1) front desk, (2) housekeeping, (3) food and beverage, (4) auxiliary facilities, (5) accounting, and (6) sales. Not everyone will become an hotelier, but lodging deeply impacts our profession and contributes uniquely to public health.', ARRAY[]::TEXT[], NULL),
    ('SPH-T 211', 'INTERNATIONAL TOURISM', '5509', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'WH 111', 'Brandon Howell', 16, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Overview of international tourism and its importance to world-wide destinations, focusing on the complexity of the world''s diverse tourism opportunities, cultures, attractions, facilities, associated natural and cultural resources, and the role of sustainability in global tourism operations. Areas of investigation will range from conventional mass tourism to alternative tourism settings.', ARRAY[]::TEXT[], NULL),
    ('SPH-T 302', 'MANAGEMENT OF FOOD & BEVERAGE OPERATIONS', '7097', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WH 004', 'Brandon Howell', 28, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course is an introduction to the fundamental principles of food and beverage management; emphasizing how food service professionals create and deliver guest-driven service, enhance value, build guest loyalty, and promote repeat business. Students learn theoretical and practical skills for effective management of food and beverage service operations relating to front and back of the house, leadership, management principles, service skills, service styles, and training of personnel.', ARRAY[]::TEXT[], NULL),
    ('SPH-T 311', 'CONV MGMT & MEETING PLANNING', '2007', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'SE 105', 'Celina Thomas', 6, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'To enhance their effectiveness in the tourism and commercial recreation industry, students should extend this programming focus to include nonrecreational facilities and services, particularly those associated with various groups and types of?meetings such as conventions, banquets, receptions, and special events.', ARRAY[]::TEXT[], NULL),
    ('SPH-T 323', 'FESTIVAL AND EVENT MANAGEMENT', '8827', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 005', 'Celina Thomas', 5, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Focus on key management, marketing and operational areas in festival & event tourism, including managing culture and leisure experiences, merchandising and retail, catering, ticketing and pricing operations, the role of politics and policy, and issues in the economics of event tourism and risk management.', ARRAY[]::TEXT[], NULL),
    ('SPH-T 335', 'ENTREPRENEURSHIP IN TOURISM, HOSPITALITY & EVENT MANAGEMENT (THEM)', '12121', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'LI 026', 'David Smiley', 0, NULL, 'Lecture', '3', 'WELLS LIBRARY', ARRAY[]::TEXT[], 'Introduction to hospitality business management theory and practice in an entrepreneurial environment within the hospitality industry. Topics include: financial and legal requirements of a startup venture, competitive market analysis, business plan development, and strategic planning. Working in teams, students develop concise presentation decks and detailed business plans in a competitive framework over the course of the semester, leading to presentations to a panel of experienced entrepreneurs.', ARRAY[]::TEXT[], NULL),
    ('SPH-T 337', 'REVENUE MANAGEMENT IN TOURISM, HOSPITALITY & EVENT MANAGEMENT (T.H.E.M.)', '12120', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'LI 026', 'David Smiley', 0, NULL, 'Lecture', '3', 'WELLS LIBRARY', ARRAY[]::TEXT[], 'This course provides students with a broad familiarization of revenue management in the hospitality industry. It presents a detailed overview of the principles used in managing the financial operations of hospitality businesses. This course will provide students with an understanding of inventory control practices and the related decisions.', ARRAY[]::TEXT[], NULL),
    ('SPH-T 389', 'GLOBAL DESTINATION MANAGEMENT', '9342', 'Closed', 'Tu Tuesday 5:45 PM–8:15 PM', 'GA 1118', 'Joseph Chen', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Understanding the process of global destination management with a focus on leadership/coordination, strategic tourism planning and product development, destination marketing, and partnership and community relations. The role of destination management organizations around the world is reviewed.', ARRAY[]::TEXT[], NULL),
    ('SPH-T 425', 'CAPSTONE IN TOURISM, HOSPITALITY, & EVENT MANAGEMENT (THEM)', '8828', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'JH 065', 'Celina Thomas', 20, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'The study of strategic and comprehensive planning, its application and processes to include management components, and various impacts and influences that help determine a destinations development. Emphasis will be placed upon the planning process, public engagement techniques, research methods, trends analysis and planning models as they relate to recreation and tourism organizations within a destination. A simulation program involving a real-time management program will be utilized in the class to apply ideas. This is the capstone class in the major.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 210', 'ENVIRONMENTAL HEALTH SEMINAR', '10741', 'Class Status', 'W Wednesday 1:30 PM–2:20 PM', 'HD TBA', 'Daniella Chusyd', 17, NULL, 'Seminar', '1', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This course will expose students to a broad range of environmental and occupational research, practice, and policy issues. Student will attend a weekly seminar presented by an invited speaker in the field of environmental and occupational health.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 215', 'FOOD PATHOGENS, TOXINS, AND SURVEILLANCE', '12041', 'Closed', NULL, 'WB WEB', 'Eduardo Ximenes', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Pathogens or toxins are associated with foodborne illnesses. This course will address: definition of food safety, insecurity and defense; pathogens and toxins, diseases, treatment and economic implications; sample preparation and detection; surveillance, control and prevention; role of regulatory agencies; food supply chain and safety; workplace safety; antimicrobial resistance; outbreaks.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 235', 'INTRODUCTION TO PUBLIC HEALTH BIOLOGY', '8482', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'LH 035', 'Eduardo Ximenes', 10, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This course will examine the biological and chemical basis for human disease, its prevention and treatment. Topics covered will include the etiologies of acute and chronic diseases and their impacts on public health.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('SPH-V 235', 'INTRODUCTION TO PUBLIC HEALTH BIOLOGY', '8355', 'Class Status', NULL, 'WB WEB', 'Barbara Hocevar', 3, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This course will examine the biological and chemical basis for human disease, its prevention and treatment. Topics covered will include the etiologies of acute and chronic diseases and their impacts on public health.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('SPH-V 235', 'INTRODUCTION TO PUBLIC HEALTH BIOLOGY', '37385', 'Class Status', NULL, 'WB WEB', 'Funmilola Ayeni', 18, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This course will examine the biological and chemical basis for human disease, its prevention and treatment. Topics covered will include the etiologies of acute and chronic diseases and their impacts on public health.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('SPH-V 235', 'INTRODUCTION TO PUBLIC HEALTH BIOLOGY', '11980', 'Closed', NULL, 'WB WEB', 'Barbara Hocevar', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This course will examine the biological and chemical basis for human disease, its prevention and treatment. Topics covered will include the etiologies of acute and chronic diseases and their impacts on public health.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('SPH-V 235', 'INTRODUCTION TO PUBLIC HEALTH BIOLOGY', '12370', 'Closed', NULL, 'WB WEB', 'Mary-Margaret Weigel', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This course will examine the biological and chemical basis for human disease, its prevention and treatment. Topics covered will include the etiologies of acute and chronic diseases and their impacts on public health.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('SPH-V 235', 'INTRODUCTION TO PUBLIC HEALTH BIOLOGY', '37384', 'Closed', NULL, 'WB WEB', 'Luis Chaves', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This course will examine the biological and chemical basis for human disease, its prevention and treatment. Topics covered will include the etiologies of acute and chronic diseases and their impacts on public health.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('SPH-V 241', 'FOUNDATIONS OF ENVIRONMENTAL HEALTH', '6478', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'GA 1100', 'Rodrigo Armijos', 1, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'An understanding of Environmental Health issues that affect Public Health is essential for any student of Public Health. This course is designed to introduce the student to the many varied areas of Environmental Health and demonstrate the important role this field plays in Public Health.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
