    ('SPH-V 241', 'FOUNDATIONS OF ENVIRONMENTAL HEALTH', '14147', 'Closed', NULL, 'WB WEB', 'Sarah Commodore', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'An understanding of Environmental Health issues that affect Public Health is essential for any student of Public Health. This course is designed to introduce the student to the many varied areas of Environmental Health and demonstrate the important role this field plays in Public Health.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('SPH-V 241', 'FOUNDATIONS OF ENVIRONMENTAL HEALTH', '29726', 'Closed', NULL, 'WB WEB', 'Drew Capone', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'An understanding of Environmental Health issues that affect Public Health is essential for any student of Public Health. This course is designed to introduce the student to the many varied areas of Environmental Health and demonstrate the important role this field plays in Public Health.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('SPH-V 241', 'FOUNDATIONS OF ENVIRONMENTAL HEALTH', '32618', 'Closed', NULL, 'WB WEB', 'Roberto Rodriguez', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'An understanding of Environmental Health issues that affect Public Health is essential for any student of Public Health. This course is designed to introduce the student to the many varied areas of Environmental Health and demonstrate the important role this field plays in Public Health.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('SPH-V 241', 'FOUNDATIONS OF ENVIRONMENTAL HEALTH', '32620', 'Closed', NULL, 'WB WEB', 'Justin Greaves', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'An understanding of Environmental Health issues that affect Public Health is essential for any student of Public Health. This course is designed to introduce the student to the many varied areas of Environmental Health and demonstrate the important role this field plays in Public Health.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('SPH-V 343', 'ENVIRONMENTAL HEALTH SAMPLING AND ANALYTICAL TECHNIQUES', '12030', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'HD TBA', 'Drew Capone', 19, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Collecting reliable and defensible environmental data requires proper sampling and analytical techniques, and is an essential job function for many environmental professionals. Currently, a diverse and diffuse array of environmental sampling and analysis tools are used in the field of environmental health. The overall objective of this class is to provide a comprehensive overview of the fundamentals of environmental sampling and analysis for students in environmental health and others interested in sampling and analytical work. Topics covered will include planning, sampling, analysis, QA/QC, and reporting with respect to air, water, solid liquid, and biological samples matrices. Active learning activities will be used to encourage class participation while maintaining interest in the course material.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 350', 'CURRENT TOPICS IN ENVIRONMENTAL AND OCCUPATIONAL HEALTH', '13274', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'HD TBA', 'Jessica Eise', 11, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This course will provide students with an overview of contemporary topics relevant to environmental and occupational health. It is intended for students with Junior or Senior status. This course number is used for temporary courses, with each section representing a distinctly separate course. This course is repeatable for credit with different topics', ARRAY[]::TEXT[], NULL),
    ('SPH-V 360', 'ENVIRONMENTAL JUSTICE AND THE ANTHROPOCENE', '13276', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'HD TBA', 'Michelle Del Rio', 4, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Environmental justice exists to the extent that all people regardless of race, income, or other social differences enjoy the same degree of protection from environmental hazards, and have equal access to environmental health decision making processes. Conversely, the course will consider the proposition that people of color and socio-economically disadvantaged individuals bear a disproportionate burden of environmental pollution and its health consequences, in the US and globally. This course is designed to orient students to concepts, foundations and evidence regarding environmental justice, including its history, challenges, and future.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 450', 'UNDERSTANDING AND PREVENTING ENVIRONMENTAL RISKS TO HUMAN HEALTH', '29673', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'HD TBA', 'Kan Shao', 8, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'How much does the environment where you live affect your health? In this class, you''ll learn how to estimate how chemical and microbial pollutants in the environment affect the health of people in a community.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 492', 'RESEARCH IN ENVIRONMENTAL AND OCCUPATIONAL HEALTH', '13041', 'Class Status', NULL, NULL, 'Patricia Silveyra', 2, NULL, 'Research', '1–3', NULL, ARRAY[]::TEXT[], 'Environmental health represents a broad discipline that involves recognizing, assessing, understanding and controlling the impacts of people in their environment and the impacts of the environment on public health. This course will provide undergraduate students with an opportunity to work on a research project under the direction of a member of the environmental and occupational health faculty. Enrollment is limited to advanced undergraduate students upon the approval of faculty', ARRAY[]::TEXT[], NULL),
    ('SPH-V 492', 'RESEARCH IN ENVIRONMENTAL AND OCCUPATIONAL HEALTH', '13042', 'Class Status', NULL, NULL, 'Luis Chaves', 6, NULL, 'Research', '1–3', NULL, ARRAY[]::TEXT[], 'Environmental health represents a broad discipline that involves recognizing, assessing, understanding and controlling the impacts of people in their environment and the impacts of the environment on public health. This course will provide undergraduate students with an opportunity to work on a research project under the direction of a member of the environmental and occupational health faculty. Enrollment is limited to advanced undergraduate students upon the approval of faculty', ARRAY[]::TEXT[], NULL),
    ('SPH-V 492', 'RESEARCH IN ENVIRONMENTAL AND OCCUPATIONAL HEALTH', '13044', 'Class Status', NULL, NULL, 'Daniella Chusyd', 1, NULL, 'Research', '1–3', NULL, ARRAY[]::TEXT[], 'Environmental health represents a broad discipline that involves recognizing, assessing, understanding and controlling the impacts of people in their environment and the impacts of the environment on public health. This course will provide undergraduate students with an opportunity to work on a research project under the direction of a member of the environmental and occupational health faculty. Enrollment is limited to advanced undergraduate students upon the approval of faculty', ARRAY[]::TEXT[], NULL),
    ('SPH-V 541', 'ENVIRONMENTAL HEALTH', '3637', 'Class Status', 'MW Monday, Wednesday 4:55 PM–6:10 PM', 'HD TBA', 'Lisa Kamendulis', 10, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Components of environmental health and public sanitation programs. Topics include water supply, air and stream pollution, sewage treatment and waste disposal, insect and rodent eradication, energy alternatives, food and drug-quality assurance, occupational health, radiological health, and communicable disease control.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 541', 'ENVIRONMENTAL HEALTH', '11499', 'Class Status', NULL, 'WB WEB', 'Lisa Kamendulis', 7, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Components of environmental health and public sanitation programs. Topics include water supply, air and stream pollution, sewage treatment and waste disposal, insect and rodent eradication, energy alternatives, food and drug-quality assurance, occupational health, radiological health, and communicable disease control.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 544', 'ESSENTIAL TOPICS IN CHILDREN''S ENVIRONMENTAL HEALTH', '29675', 'Class Status', NULL, 'WB WEB', 'Michelle Del Rio', 25, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course focuses on required abilities to practice in children''s environmental health field. Children''s vulnerabilities to environmental exposures and emergencies and associated physical and mental health impacts will be discussed. Emphasis is on data mining and reporting to support surveillance and learning about policies that protect children and the environment.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 546', 'RISK ASSESSMENT, POLICY AND TOXIC REGULATIONS', '29674', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'HD TBA', 'Kan Shao', 16, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Covers hazard identification, dose-response assessment, exposure assessment, and risk characterization. Through case studies, addresses concepts of risk management and their application to environmental health policies and toxic regulations.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 546', 'RISK ASSESSMENT, POLICY AND TOXIC REGULATIONS', '32619', 'Class Status', NULL, 'WB WEB', 'Kan Shao', 9, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Covers hazard identification, dose-response assessment, exposure assessment, and risk characterization. Through case studies, addresses concepts of risk management and their application to environmental health policies and toxic regulations.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 548', 'ENVIRONMENTAL AND OCCUPATIONAL EPIDEMIOLOGY', '13275', 'Class Status', 'Th Thursday 3:10 PM–6:00 PM', 'HD TBA', 'Mary-Margaret Weigel', 17, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Examines effects of environmental factors on human health. Covers the health effects from exposure to physical, chemical and biological agents including the contribution of social, economic and cultural factors that are related to these exposures.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 548', 'ENVIRONMENTAL AND OCCUPATIONAL EPIDEMIOLOGY', '11736', 'Class Status', NULL, 'WB WEB', 'Mary-Margaret Weigel', 14, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Examines effects of environmental factors on human health. Covers the health effects from exposure to physical, chemical and biological agents including the contribution of social, economic and cultural factors that are related to these exposures.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 560', 'ENVIRONMENTAL JUSTICE', '13277', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'HD TBA', 'Michelle Del Rio', 4, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'The course will consider the proposition that people of color and socio-economically disadvantaged individuals bear a disproportionate burden of environmental pollution and its health consequences, in the US and globally. This course is designed to orient students to concepts and evidence regarding environmental justice, including its history, challenges, and future.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 598', 'GRADUATE RESEARCH PROJECT', '34783', 'Closed', NULL, 'HD TBA', 'Justin Greaves', 0, NULL, 'Research', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Participate in a research project related to environmental and/or occupational health. Designed to provide non-thesis graduate students with research experience in environmental and/or occupational health.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 599', 'MASTER''S THESIS', '37118', 'Class Status', NULL, 'WB WEB', 'Funmilola Ayeni', 1, NULL, 'Research', '1–6', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Thesis research focused in an area of environmental and/or occupational health under the direct supervision of a graduate faculty member.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 691', 'READINGS IN ENVIRONMENTAL HEALTH', '14290', 'Class Status', NULL, NULL, 'Justin Greaves', 2, NULL, 'Readings', '1–3', NULL, ARRAY[]::TEXT[], 'Planned readings in specialized areas of professional interests in environmental health are conducted under the direction of a member of the Environmental Health graduate teaching faculty. Enrollment is limited to Advanced Graduate students, and reading proposals must be approved by faculty in Environmental Health.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 692', 'RESEARCH IN ENVIRONMENTAL HEALTH', '14151', 'Class Status', NULL, NULL, 'Funmilola Ayeni', 2, NULL, 'Research', '1–3', NULL, ARRAY[]::TEXT[], 'Research projects are conducted under the direction of a member of the Environmental Health Graduate teaching faculty. Enrollment is limited to Advanced Graduate Students upon the approval of Faculty.', ARRAY[]::TEXT[], NULL),
    ('SPH-V 692', 'RESEARCH IN ENVIRONMENTAL HEALTH', '14156', 'Class Status', NULL, NULL, 'Michelle Del Rio', 2, NULL, 'Research', '1–3', NULL, ARRAY[]::TEXT[], 'Research projects are conducted under the direction of a member of the Environmental Health Graduate teaching faculty. Enrollment is limited to Advanced Graduate Students upon the approval of Faculty.', ARRAY[]::TEXT[], NULL)
